INSERT INTO random VALUES (1, 'Of course, to one as modern as I am, the world will always be beautiful. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (2, 'The bond of all companionship, whether in marriage or in friendship, is conversation. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (3, 'It is a much cleverer thing to talk nonsense than to listen to it. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (4, 'What a pity that in life we only get our lessons when they are of no use to us. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (5, 'No gentleman ever has any money. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (6, 'The supreme vice is shallowness. - Oscar Wilde', 'quote');
INSERT INTO random VALUES (7, 'All you need to make a movie is a girl and a gun. - Jean-Luc Godard', 'quote');
INSERT INTO random VALUES (8, 'To be conscious that you are ignorant is a great step to knowledge. - Benjamin Disraeli, <I>Sybil</I>', 'quote');
INSERT INTO random VALUES (9, 'Ignorance is not innocence but sin. - Robert Browning', 'quote');
INSERT INTO random VALUES (10, 'Not to know is bad; not to wish to know is worse. - Nigerian Proverb', 'quote');
INSERT INTO random VALUES (11, 'I love deadlines. I like the whooshing sound as they fly by. - Douglas Adams', 'quote');
INSERT INTO random VALUES (12, 'What force is more potent than love. - Igor Stravinsky', 'quote');
