INSERT INTO random VALUES (26, 'The girl who can\'t dance says the band can\'t play - Yiddish Proverb', 'quote');
INSERT INTO random VALUES (27, 'Problems are only opportunities in work clothes. - Henry J. Kaiser', 'quote');
INSERT INTO random VALUES (28, 'It is impossible to love and to be wise. - Francis Bacon', 'quote');
INSERT INTO random VALUES (29, 'When the rich make war it\'s the poor that die. - Jean-Paul Sartre', 'quote');
INSERT INTO random VALUES (30, 'Hell is other people! - Jean-Paul Satre', 'quote');
INSERT INTO random VALUES (31, 'Something is rotten in the state of Denmark - William Shakespeare (Hamlet, Act I, Scene IV)', 'quote');
INSERT INTO random VALUES (32, 'He who can, does. He who cannot, teaches. - George Bernhard Shaw', 'quote');
INSERT INTO random VALUES (33, 'Democracy substitutes election by the incompetent many for appointment by the corrupt few. - George Bernhard Shaw', 'quote');
INSERT INTO random VALUES (34, 'In the middle of difficulty lies opportunity. - Albert Einstein', 'quote');
INSERT INTO random VALUES (35, 'A wise man will make more opportunities than he finds. - Francois Bacon', 'quote');
INSERT INTO random VALUES (36, 'Adversity reveals genius, prosperity conceals it. - Horace', 'quote');
INSERT INTO random VALUES (37, 'Take care to get what you like or you will be forced to like what you get. - George Bernhard Shaw', 'quote');
INSERT INTO random VALUES (38, 'This is your life and it\'s ending one minute at a time. - Fight Club', 'quote');
INSERT INTO random VALUES (39, 'Our generation has had no Great Depression, no Great War. Our war is spiritual. Our depression is our lives. - Fight Club', 'quote');
INSERT INTO random VALUES (40, 'I am Jack\'s smirking revenge. - Fight Club', 'quote');
INSERT INTO random VALUES (50, 'It\'s only after you\'ve lost everything that you\'re free to do anything. - Fight Club', 'quote');
INSERT INTO random VALUES (42, 'You are not special. You are not a beautiful or unique snowflake. You are the same decaying organic matter as everything else. - Fight Club', 'quote');
INSERT INTO random VALUES (49, 'On a long enough timeline, the survival rate for everyone drops to zero. - Fight Club', 'quote');
INSERT INTO random VALUES (47, 'We were raised on television to believe that we\'d all be millionares, movie gods, rock stars, but we won\'t. And we\'re starting to figure that out. - Fight Club', 'quote');
INSERT INTO random VALUES (48, 'We are a generation of men raised by women. I\'m beginning to wonder if another woman is what we really need. - Fight Club', 'quote');
INSERT INTO random VALUES (45, 'You are not your job. You are not the money in your bank account. You are not the car you drive. You are not how much money is in your wallet. You are not your fucking khakis. You are the all-singing, all-dancing crap of the world. - Fight Club', 'quote');
INSERT INTO random VALUES (46, 'Self improvement is masturbation. Self destruction is the answer. - Fight Club', 'quote');
INSERT INTO random VALUES (51, 'Right. Well, I have to--I have to go now, Duane, because I, I\'m due back on the planet Earth. - Annie Hall', 'quote');
INSERT INTO random VALUES (52, 'What\'s with all these awards? They\'re always giving out awards! Best Fascist Dictator: Adolf Hitler! - Annie Hall', 'quote');
INSERT INTO random VALUES (53, 'Hey, don\'t knock masturbation! It\'s sex with someone I love. - Annie Hall', 'quote');
INSERT INTO random VALUES (54, 'I don\'t want to achieve immortality through my work, I want to achieve it by not dying. - Woody Allen', 'quote');
INSERT INTO random VALUES (55, 'I\'m not afraid of dying...I just don\'t want to be there when it happens. - Woody Allen', 'quote');
INSERT INTO random VALUES (56, 'Tradition is the illusion of permanence. - Deconstructing Harry', 'quote');
INSERT INTO random VALUES (57, 'Does the president think of fucking every woman he meets? Oh sorry, bad example. - Deconstructing Harry', 'quote');
INSERT INTO random VALUES (58, 'Achilles only had an Achilles heel, I have an entire Achilles body. - Mighty Aphrodite', 'quote');
INSERT INTO random VALUES (59, 'Of all human weaknesses, obsession is the most dangerous, and the silliest! - Mighty Aphrodite', 'quote');
INSERT INTO random VALUES (60, 'I see disaster. I see catastrophe. Worse, I see lawyers! - Mighty Aphrodite', 'quote');
INSERT INTO random VALUES (61, 'I think it would be fun to run a newspaper. - Citizen Kane', 'quote');
INSERT INTO random VALUES (62, 'Harvard, Yale, Princeton, Cornell, Switzerland... he was thrown out of a lot of colleges. - Citizen Kane', 'quote');
INSERT INTO random VALUES (63, 'I\'m not very fond of movies. I don\'t go to them much. - Orson Welles', 'quote');
INSERT INTO random VALUES (64, 'He was the most talented man I\'ve ever worked with - indeed, ever seen. - Charlton Heston on Orson Welles', 'quote');
INSERT INTO random VALUES (65, 'He\'s a nut-bag! Just because the fucker\'s got a library card doesn\'t make him Yoda! - Seven', 'quote');
INSERT INTO random VALUES (67, 'Ernest Hemingway once wrote, \'The world is a fine place and worth fighting for.\' I agree with the second part. - Seven', 'quote');
INSERT INTO random VALUES (74, '"Hannah: Do you think you could have ruined yourself some way? <i>Like what?</i> Excessive masturbation? <i>Now you\'re knocking my hobbies, Jesus!</i>" - Woody Allen, Hannah and Her Sisters', 'quote');
INSERT INTO random VALUES (72, 'What no spouse of a writer can ever understand is that a writer is working even when he is staring out the window.', 'quote');
INSERT INTO random VALUES (73, 'Charles Foster Kane is a monster, and a committe should be formed against him.  If you form such a committe, put me down for a donation of one thousand dollars. - Charles Foster Kane, <I>Citizen Kane</I>', 'quote');
INSERT INTO random VALUES (70, 'I\'m hungry. Let\'s get a taco. - Reservior Dogs', 'quote');
INSERT INTO random VALUES (71, 'Get busy living, or get busy dying - Shawshank Redemption', 'quote');
INSERT INTO random VALUES (75, 'Thunt.net - Hiding behind the first amendment since 1979.', 'quote');
INSERT INTO random VALUES (76, 'Never believe <i>anything</i> you read on Thunt.net - Thomas Hunt', 'quote');
INSERT INTO random VALUES (77, 'Whenever you run out of material, I suggest faking your own death.  - Thomas Hunt', 'quote');
INSERT INTO random VALUES (78, 'People thought it\'s abrupt, and well, they can just go fuck themselves - P.T. Anderson on <I>Sydney</I>', 'quote');
INSERT INTO random VALUES (79, 'The meek shall inherit the earth, but not its mineral rights. - Albert Einstein', 'quote');
INSERT INTO random VALUES (80, 'Only two things are infinite, the universe and human stupidity, and I\'m not sure about the former. - Albert Einstein', 'quote');
