INSERT INTO random VALUES (84, 'The mark of an immature man is that he wants to die nobly for a cause, while the mark of a mature man is that he wants to live humbly for one. - William Stekel', 'quote');
INSERT INTO random VALUES (85, 'Freedom of the press is limited to those who own one. - A.J. Liebling', 'quote');
INSERT INTO random VALUES (86, 'I\'m not prejudiced, I hate everyone equally.', 'quote');
INSERT INTO random VALUES (87, 'They\'re giving bank robbing a bad name.  -- John Dillinger, on Bonnie and Clyde', 'quote');
