INSERT INTO thuntnet_archive VALUES (5, 'Thunt.net IV: the database', 'Thomas Hunt', 'thunt@thunt.net', '\r\nThunt.net is now a database.\r\n\r\nWhat does that mean to you?  Not a whole lot. \r\n\r\nWhat does this mean to me?  I can continue thunt.net\'s path to \r\ninnovation.  Now all of the data is stored as text in a massive excel \r\nspreadsheet called a database.  \r\n\r\nWhat about the old thunt.net?  Well, I\'m going to think about it a while.  \r\nI\'m going to compile it all to a dir so the search engine might pick it \r\nup.  Then I\'m thinking about re-entering it into the database in \r\nchunks like a "Thunt.net Flashbacks" section or something....\r\n\r\nIn other news, I\'m wrote a description for a PHP Hat at CopyLeft.  They \r\nhad a link that said they couldn\'t think of anything,\r\nso I sent them this:\r\n\r\n<i>Guaranteed to fit any size brainpan from guru to \r\nnewbie, this PHP hat is a definite must for any PHP \r\ncoder.</i>\r\n\r\nAnd within minutes I recieved an email saying that \r\nthey liked it and they put it up.  Pretty cool huh?\r\n\r\nThat\'s it for me, from New Thunt.net :>\r\n', 'the database owns.', 20000718214014, 'normal', '');
INSERT INTO thuntnet_archive VALUES (6, 'Snazzy Wallpapers', 'Thomas Hunt', 'thunt@thunt.net', '', 'Awesome site for snazzy techno wallpapers.', 20000718214128, 'net_interest', 'chapter3.net');
INSERT INTO thuntnet_archive VALUES (7, 'Paper Shredders are cool', 'Thomas Hunt', 'thunt@thunt.net', '  I just shredded some paper in a paper shredder.  It may sound odd, but \r\nI\'ve never shredded anything before, and it kicked ass.  A little loud, \r\nbut still very fun.\r\n  I think that people who like jigsaw puzzles should just buy a paper \r\nshredder and then shred something.  They could start with a one page \r\ndocument as their "level 1" puzzle.  Then work their way up to thesis’s \r\nand small books.  Proffessional shredder puzzle masters could compete \r\nusing encylopedias and Tolstoy books.  People who like crossword puzzles \r\ncould also benefit from paper shredders by shredding themselves.\r\n  Once, in High School Debate I made an impromptu speech to a crowd of 30-\r\n40 of my fellow debators and one angry judge.  It was an abstract speech, \r\nI was handed a card with a word on it, and given three minutes of prep \r\ntime and then I was to deliver a five minute speech.  My word was Irony.  \r\nI gave a stunning oratory of seven minutes.  My main example was the great \r\nirony involved in shredding the instructions to a paper shredder.  I \r\nfurthur delved into the depths of this example by explaining the poor case \r\nof someone who had boldly shredded the instructions to a paper shredder \r\nand then called their tech support line asking how to adjust the settings \r\non his shredder.  The tech support line of course asked him if he had the \r\ninstructions and he was of course left in the unsatisfactory condition of \r\nhaving to explain what he did.  How ironic.  Of course, the crowd loved \r\nthe speech and so did the judge.  I won first place in the Novice \r\nImpromptu Speaking catagory.  It was my first time competing in the \r\ncatagory.  I still have the trophy on my mantle at home.  The next time I \r\ncompeted it was on the Varisty level and I won third place.\r\n', 'Did you see that part in Batman Returns when Penguin showed Max Schrex the notes that had been shredded that he re-assembled?  That was cool.', 20000719172209, 'normal', '');
INSERT INTO thuntnet_archive VALUES (1, 'Comming Soon', 'Thomas Hunt', 'thunt@thunt.net', '  The new thunt.net is definately new and spiffy, but \r\nour thunt.net engineers are constantly working to \r\nbring new and groovy innovations to your thunt.net \r\nviewing experience.  Here\'s just a few of the gems \r\nthat we currently have in development.\r\n\r\n  - Better Search Engine for Thunt.net\r\n  - Special Sections\r\n  - User Preferences\r\n     - Skins for thunt.net\r\n     - No side boxes or more side boxes.\r\n     - more headlines or less\r\n     - a completely \'interactive\' viewing experience\r\n  - Thunt.net Email notification\r\n     - It keeps you constantly informed when    \r\n       thunt.net has been updated.\r\n  - Thunt.net Forum\r\n     - Discuss Thunt.net with other Thunt.net viewers\r\n\r\nAnd much much more.\r\n\r\n', 'Outlines the great new features we are working on for thunt.net.', 20000718204357, 'normal', '');
