INSERT INTO thuntnet_archive VALUES (103, 'DEFCON Music Video Released', 'Thomas Hunt', 'thunt@thunt.net', '\r\nYes that\'s right. Years of poking and prodding have finally taken their \r\ntoll as Thunt releases the DEFCON Music Video.  You must see it.  You must \r\nsee it now.  There can be no waiting.  Yes there can not be any waiting. \r\n\r\nYou must go to \r\n<a href="http://thunt.net/defcon">http://thunt.net/defcon/defcon</a> \r\nand watch the music video.  \r\n\r\n(Yes this is just the music video.  Expect the ten minute \'epic\' Voyage of \r\nthe good ship Nosferatu III to be released any day now.)\r\n\r\n', '\r\nYes that\'s right. Years of poking and prodding have finally taken their toll as Thunt releases the DEFCON Music Video.  You must see it.  You must see it now.  There can be no waiting.  Yes there can not be any waiting. \r\n', 20001024101941, 'normal', '');
