INSERT INTO thuntnet_archive VALUES (82, 'Save Thunt Campaign Continues', 'Mark Anthony & Ryan Anne Polli', 'thunt@thunt.net', '  Good news from the front!  The Save Thunt Campaign is continuing in the \r\nfield, from the midwest all the way to the Kentucky Derby.  Keep up the \r\ngood work and with God\'s help, Thunt will survive!\r\n\r\n</pre>\r\n<center>\r\n   <img src="images/save_thunt/savethunt_barn.jpg"><br>\r\n<font class="normal">The Nebraskan Thunt.net Group</font><br>\r\n<br>\r\n   <img src="images/save_thunt/savethunt_horse.jpg"><br>\r\n<font class="normal">Thunt.net supported by the Kentucky Derby!</font><br>\r\n<br>\r\n<pre class="normal">\r\n\r\nphotos by <a href="mailto:il_disegno@yahoo.com">\r\nRyan Anne Polli</a>\r\n', 'Thunt.net campaign hits the midwest.', 20001009214000, 'normal', '');
