INSERT INTO thuntnet_archive VALUES (120, 'Movie Review: Son-in-law (1993)', 'Thomas Hunt', 'thunt@thunt.net', '	Pauly Shore stars in this most striking social commentary ever to \r\ncome out of the early nineties.  Shore plays a mentally retarded man who \r\nescapes from a mental asylum in California by pretending to be engaged to \r\na sweet Midwestern country girl.  Upon his arrival to the Midwest, it \r\nquickly becomes clear that Shore is not the most retarded character in \r\nthis film. The Midwest people show themselves to be at least twice as \r\nretarded.  From the sweet midwestern girl who believes her fake engagement \r\nto Shore is a real engagement, to the entire dysfunctional family.  The \r\ninsanity of Shore\'s character spreads like a vicious virus through this \r\nmidwestern family. The matron character soon learns that if she puts on a \r\nlittle makeup she can easily entice her husband.  In this scene, the \r\nhusband, preparing to make his conquest, performs the mating ritual of \r\npushing the two beds together, followed by the stylish rooster imagery \r\nthat of course represents cock.\r\n	Shore\'s acting can only be characterized by the word amazing.  The \r\ndramatic range portrayed while playing this mentally retarded character is \r\ntruly unbelievable.  The most incredible aspect of his performance is his \r\ncreation of new words such as "grindage", "bone her" and "cones".  The \r\nperformance is far better than Geoffrey Rush\'s performance in Shine or \r\nGeorge W. Bush\'s performance in the recent Presidential election.\r\n	Other film critics who fail to see the depth of Shore’s portrayal \r\nmay overlook this film, but it is a truly excellent film representing the \r\ntrue heights of this powerful force in acting.  I cannot recommend it \r\nenough.\r\n\r\n<i>Thomas Hunt is a world renown film critic and recently watched Son-in-\r\nlaw for free on digital cable</i>\r\n', '', 20001129185703, 'normal', '');
