INSERT INTO thuntnet_archive VALUES (122, 'Something you should read, and then dedicate your life to.', 'Thomas Hunt', 'thunt@thunt.net', 'Hunter S. Thompson.  One of the greatest writers of all of American \r\nHistory has begun writing articles, weekly, at ESPN.com\'s <a \r\nhref="http://espn.go.com/page2">Page 2</a>.\r\n  You must read them all.  You must read all of the new ones. \r\n They come every week.  You must read them all.\r\n\r\n<UL><B>\r\nHunter S. Thompson at Page2</B>\r\n<a href="http://espn.go.com/page2/s/thompson/001127.html">\r\n<LI>The fix is in</a>\r\n<a href="http://espn.go.com/page2/s/thompson/001120.html">\r\n<LI>Prepare for the Weirdness</a>\r\n<a href="http://espn.go.com/page2/s/thompson/001113.html">\r\n<LI>Just binge, baby!</a>\r\n<a href="http://espn.go.com/page2/s/thompson/001106.html">\r\n<LI>Baseball has become unruly</a>\r\n</UL>\r\n', '', 20001202174530, 'normal', '');
