INSERT INTO thuntnet_archive VALUES (173, 'Hornet Hooker on Fox News', 'Thomas Hunt', 'thunt@thunt.net', '\r\nWell, it appears that sometimes you can get away with running a shameless \r\nadvertisement for a hooker and sometimes you can\'t.  The video is about \r\nhow one student newspaper ran into a bit of trouble when they ran a story \r\nabout a 31 year old hooker who attends classes between her \'busy\' schedule.\r\n\r\nHighlights include:\r\n 1. The story is in the Features Section, but the Editor-In-Crook \r\ndescribes it as "News".\r\n 2. The reporter is shocked because "everyone read the whole article" \r\nright after she asked them to read the article.  Imagine people being \r\npolite enough to read the entire article before commenting on it. SHOCKING!\r\n 3. The Editor-in-Thief seems to be shopping from the dumpster collection, \r\nplease note the decayed look of the sweatshirt he\'s wearing.  It\'s clear \r\nthat it\'s been in and out of trash cans digging for those cans like the \r\nrest of the hunter/gathers.\r\n 4. Note the way that the Naughty Newspaper used words that the TV Network \r\ncovered up.  It\'s amazing what you can get away with in an article when \r\nyou don\'t understand journalism.\r\n 5. The TV Station also made a really cool "animation" of the newspaper \r\nbeing unfolded and the Dirty Section coming out.  The way it was coming \r\nwas really cool.\r\n\r\nWell, that\'s about it.  We\'ll have the video up tomorrow, it\'s still \r\ncompressing right now and we\'ve gotta sleep.  Unlike some Thirty-something \r\nTransvestites, we actually go to our classes.  Thanks for reading \r\nThunt.net, the place where you watch the paper go from pacemaker to \r\npornography in just one year.  What a difference a little leadership makes.\r\n', '', 20010226233850, 'normal', '');
INSERT INTO thuntnet_archive VALUES (174, 'Hornet Hooker on Fox News, Video', 'Thomas Hunt', 'thunt@thunt.net', 'Welcome to the encore video presentation of "The Hornet Hooker on Fox \r\nNews".  My name is Thomas Hunt, and I\'ll be your host tonight.  First I\'d \r\nlike to thank our hard working crew at Thunt.net for getting this video \r\nout so quickly and with such grace.  Props go to Matt Brown for capturing, \r\nediting and outputting this video.  Matt did a great job, and everyone \r\nshould give him a pat on the back the next time they see him for his \r\nendless dedication to Thunt.net.  I\'d also like to thank myself for \r\nsetting up the tape and pushing record.  It was a hard job.  Furthurmore \r\nI\'d like to thank Joe Rodreguez for hanging out and playing Crazy Taxi \r\nwith me while Matt slaved over the editing machine.  And now, without \r\nfurthur ado, here\'s "The Hornet Hooker on Fox News".\r\n\r\n</pre>\r\n<a href="http://thunt.net/video/fox40_news.mov">View the Video</a> \r\n(QuickTime 4.0)<br>\r\n<BR>\r\n<a href="http://www.apple.com/quicktime/download/indext.html">\r\n<img \r\nsrc="http://a772.g.akamai.net/7/772/51/5a53f685ca8486/www.apple.com/quickti\r\nme/images/quicktime3download.gif"></a>\r\n<br>\r\n<pre class="normal">\r\n\r\nPS: You kids at home know who the hornet hooker is right?\r\n\r\n\r\n\r\n', '', 20010227220239, 'normal', '');
