INSERT INTO thuntnet_archive VALUES (177, 'You\'ve got Parody', 'Thomas Hunt', 'thunt@thunt.net', 'Just dropping a brief note to you, the loyal readers of Thunt.net, that \r\nI\'ve added yet another skin for you to allow you to make the most of your \r\nThunt.net experience.\r\n\r\nSimply click on <a href="http://thunt.net/fuckstatehornet2/">this link</a>\r\nor check out "Thunt.net - State Hornet Style v2.0" on the NetWork section \r\nof the sidebar...\r\n\r\nThunt.net, providing parody for the people.\r\n\r\nPS: I forgot to mention in my Hornet Hooker article who told me about the \r\nnewscast.  A little bird told me.  He said he wanted to identified as Big \r\nBird, but I felt that would be a copyright violation, so I\'m calling her \r\nlittle bird.  Good Job Bird.  That is all.', '', 20010301073152, 'normal', '');
INSERT INTO thuntnet_archive VALUES (178, 'Kung Fu and Water, a film by Andrew Duong', 'Thomas Hunt', 'thunt@thunt.net', 'We have a special treat for all of you loyal thunt.net viewers, on this \r\nrainy friday morning: The World Premiere of Andrew Duong\'s epic \r\nmasterpiece: <b>Kung Fu and Water</B>.  It\'s a very impressive film that \r\nif it had been released earlier in the year would have easilly stolen the \r\noscar nomination from Crouching Tiger, Hidden Dragon.  The film is a true \r\nclassic, not to be confused with your normal everyday home video.  But, I \r\nbelieve that I have hyped it enough.  So, without furthur ado, I give you: \r\n<B>Kung Fu and Water</B>\r\n\r\n</pre>\r\n<font class="normal">\r\n<a href="http://thunt.net/video/kung_fu_and_water_normal.mov">Kung Fu and \r\nWater</a> (Quicktime 4.0)<br>\r\n<BR>\r\n<center><a href="http://www.apple.com/quicktime/download/indext.html">\r\n<img \r\nsrc="http://a772.g.akamai.net/7/772/51/5a53f685ca8486/www.apple.com/quickti\r\nme/images/quicktime3download.gif"></a>\r\n</center><BR>\r\n<BR>\r\nAlso as a special treat for the film connoisseurs in the audience, We at \r\nthunt.net present exclusive scene-specific commentaries for Kung Fu and \r\nWater.  Enjoy!<BR>\r\n<BR>\r\n<a \r\nhref="http://www.thunt.net/video/kung_fu_and_water_andy.mov">Commentary \r\nwith director Andrew Duong</a><br>\r\n<br>\r\n<a \r\nhref="http://www.thunt.net/video/kung_fu_and_water_matt.mov">Commentary \r\nwith editor Matt Brown</a><br>\r\n<br>\r\n<a \r\nhref="http://www.thunt.net/video/kung_fu_and_water_thunt.mov">Commentary \r\nwith producer Thomas Hunt</a><br>\r\n<br>\r\n<a href="http://www.thunt.net/video/kung_fu_and_water_joe.mov">Commentary \r\nwith roomate Joe Rodregeiz</a><br>\r\n<br>\r\n<a \r\nhref="http://www.thunt.net/video/kung_fu_and_water_dick.mov">Commentary \r\nwith critic Dick Dooem</a><br>\r\n<br>\r\n<a \r\nhref="http://www.thunt.net/video/kung_fu_and_water_john.mov">Commentary \r\nwith critic John Humphries</a><br>\r\n</font>\r\n<pre class="normal">\r\nwe iz all over this shit like the cricterion collection. \r\nwe da bomb.\r\n', '', 20010302092427, 'normal', '');
INSERT INTO thuntnet_archive VALUES (179, 'Liberation Musicology', 'Thomas Hunt', 'thunt@thunt.net', '', '', 20010302181031, 'net_interest', 'http://www.thenation.com/doc.mhtml?i=20010312&s=moglen');
INSERT INTO thuntnet_archive VALUES (180, 'Hornet Jeep towed & objective journalism', 'Thomas Hunt', 'thunt@thunt.net', '</pre>\r\n<center>\r\n<a href=http://thunt.net/thuntphotos/roll01/14.jpg>\r\n<img src=http://thunt.net/thuntphotos/roll01/14.small.jpg>\r\n</a>\r\n<a href=http://thunt.net/thuntphotos/roll01/15.jpg>\r\n<img src=http://thunt.net/thuntphotos/roll01/15.small.jpg>\r\n</a>\r\n<a href=http://thunt.net/thuntphotos/roll01/16.jpg>\r\n<img src=http://thunt.net/thuntphotos/roll01/16.small.jpg>\r\n</a>\r\n<br>\r\n<a href=http://thunt.net/thuntphotos/roll01/17.jpg>\r\n<img src=http://thunt.net/thuntphotos/roll01/17.small.jpg>\r\n</a>\r\n<a href=http://thunt.net/thuntphotos/roll01/18.jpg>\r\n<img src=http://thunt.net/thuntphotos/roll01/18.small.jpg>\r\n</a>\r\n<br>\r\n</center>\r\n<pre class=normal>\r\nI recall it just like it was yesterday.  I was driving to my distant \r\nparking spot at a school that is all too near in my memory when I saw the \r\nhornet jeep hooked up to an orange facilities management tow truck.  My \r\nfirst thought was: “Holy Shit! Do I have my camera?”  The fortunate \r\nanswer was yes.  I did have my camera, due to my recent idea to shoot the \r\nroll of film I found in my desk.  I pulled my car into the lot and quickly \r\ndouble parked it and preceded to take pictures of the jeep being towed.  I \r\nhad a great story on my hands, right?  The hornet jeep being towed, talk \r\nabout symbolism, talk about the destruction of a once decent paper, talk \r\nabout incompetence.  My first thoughts were that it was towed because it \r\nwas parked in the ECS parking lot, not in it’s normal spot by the Union.  \r\n\r\nWith these ideas and these photos I could have had a great story, a \r\nheadliner, a true breakthrough for Thunt.net.  But ladies and gentlemen, \r\nthis is where we learn a lesson about journalism.  Check the facts.  Being \r\nthe good Samaritan I am, I parked my car and walked to the Hornet office \r\nto inform them that their jeep was being towed.  I rang the bell and the \r\nHornet’s friendly secretary “D” (for her security we have removed her name \r\nfrom this publication.) walks out and greets me politely, for as you all \r\nknow I once worked at the Hornet and “D” once hooked me up with free movie \r\ntickets.  I informed her that the hornet jeep was being towed and she told \r\nme that they were having it towed because a wheel had fallen off.  I \r\nnodded my head in understanding and she thanked me for the heads up.  See \r\nhow checking the facts can really effect a story?  Unlike the journalists \r\nof the Hornet, the journalists of Thunt.net always check their sources.  \r\nNow the facts of the story read: “Hornet Jeep towed due to wheel falling \r\noff” rather than “Hornet Jeep towed due to parking violation”.  That is \r\nthe difference between fact and fiction.  Also note the objectivity of the \r\njournalist, who did not point out that the wheel falling off is a much \r\ngreater symbol than it just being towed for the mere carelessness of a \r\npoor parking job.  This has been Thomas Hunt in Sacramento, for Thunt.net \r\nSpecial Reports.\r\n', '', 20010303103136, 'normal', '');
INSERT INTO thuntnet_archive VALUES (181, 'All your base are belong to us', 'Thomas Hunt', 'thunt@thunt.net', '', '', 20010303123712, 'net_interest', 'http://www.theregister.co.uk/content/28/17122.html');
INSERT INTO thuntnet_archive VALUES (182, 'Tiffany Infamy', 'Thomas Hunt', 'thunt@thunt.net', '”Wednesday March 7, 2001 is a day that will live in Infamy.”\r\n                                             -	FDR\r\n\r\nFDR was correct in the heady days of 1941 when he spoke the above, now \r\nimmortal words.  March 7th will be a day that will live in infamy.  March \r\n7th is the day when Tiffany is coming to Sac State.\r\n\r\nTiffany, as you all know is a very special artist because she, like Cher, \r\nMadonna and Hammer is referred to only by the artists’ first name.  This \r\nis essential to being a success and a timeless master.  Also Tiffany is \r\nimportant because she was the Brittany Spears of the 80s.  Her star rose \r\nfast and quickly fell back to the earth, as we all hope Brittany’s will.  \r\n(preferably falling back to the earth as a career in hard-core pornography)\r\n\r\nMarch 7th will be a special day.  I invite all of you to join me to \r\nwitness the ultimate degradation of a human being.  We are all great fans \r\nof the human tragedy.  I know you share my fascination with the morbid \r\nfailures of society because you probably worked for CampusEngine.com or \r\nare familiar with the horrid failure currently running the paper that will \r\nremain nameless.  These failures are important to society because they are \r\nabsolutely hilarious.  This is why I ask you to join me at the Tiffany \r\nshow.  Tiffany was once a star.  Her only hit “I think we’re alone now” \r\nwas parodied excellently by Weird Al Yankovic (“I think I’m a clone \r\nnow”).  This was no doubt the high point of her career, to be parodied by \r\nsuch a great artist.  Now, if you will join me as we watch what can only \r\nbe considered the lowest point of her career.  Wednesday she will play for \r\na crowd of no more than 10.  She is playing at “Joe Serna Plaza” or “The \r\nlawn behind the Union”.  She is playing at noon.  Most people will stand \r\nin line getting food rather than watch the show.  She is playing for \r\nfree.  There is no admission to this “concert” but I doubt that the \r\naudience will rise much above 10 people.  Furthermore she hasn’t been a \r\nstar since the 80s and it is now the 90s.  If she had any attractiveness \r\nbefore it has no doubt long since withered.  Additionally what other songs \r\ncan she perform besides “I think we’re alone now”, which she will no doubt \r\nsave until the end like a card cheat dealing off the bottom of the deck.  \r\n\r\nI invite you to witness this human in misery.  I will be there.  And so \r\nwill my video camera.  We will be filming interviews with whoever is there \r\nas well as trying to capture the feel of this “concert”.  I guarantee you \r\nwill have a good time.  Please RSVP by emailing <a \r\nhref=mailto:thunt@thunt.net>thunt@thunt.net</a>.  I hope to see you there.\r\n\r\n', '', 20010305205639, 'normal', '');
INSERT INTO thuntnet_archive VALUES (186, 'Tiffany: The Autograph', 'Thomas Hunt', 'thunt@thunt.net', '</pre>\r\n<center>\r\n<a href=http://thunt.net/images/tiffany/tiff_auto_large.jpg>\r\n<img src=http://thunt.net/images/tiffany/tiff_auto_small.jpg>\r\n</a>\r\n<br>\r\n"To Thunt.net, Love Tiffany"<br>\r\n<br>\r\n<pre class=normal>\r\nAndrew Duong went above and beyond the call of duty, even venturing into \r\nTiffany\'s trailer to get this beautiful autographed photo for Thunt.net.  \r\nGood job Andy!\r\n\r\n', '', 20010309100958, 'normal', '');
INSERT INTO thuntnet_archive VALUES (184, 'Tiffany: The show in words', 'Thomas Hunt', 'thunt@thunt.net', 'Nostalgia is a powerful force ladies and gentlemen.  Nostalgia and \r\nthunt.net  The Tiffany show was an amazing event.  There were hundreds of \r\npeople there and it didn’t rain.  What does this show?  The power of \r\nCelebrity.  Tiffany was once famous.  The people in the audience were not \r\nall Tiffany fans.  Most of them probably did by her record then and they \r\nprobably won’t buy it now.  But regardless of their various levels of \r\nfandom they were all united by their incredible obsession with famous \r\npeople.\r\n\r\nTiffany was once famous.  In those days she was a cute 14-year old Mall \r\nQueen Pop Star.  Now she’s a twenty nine year old mother of one.  The \r\nyears have been both hard and soft on Tiffany.  Her tight spandex pants \r\nhide little from this reporter’s sight.  Her breasts are sagging but she \r\nremains attractive.  Attractive enough to regain her pop stardom and \r\ncompete with the likes of Jennifer Lopez, Christina, Aguliera and Britney \r\nSpears?  In the view of this jaded correspondent, not a chance.\r\n\r\nEnough about the appearance of this aging has been.  On to the music.  \r\nTiffany played mostly new material on this sunny winter day.  Her songs \r\nare an eclectic mix of the tired style of Alanis Morrissette, Sarah \r\nMcLachlan, and Shania Twain.  The lyrics are uninteresting and the band is \r\naverage.  \r\n\r\nBut the crowd was overjoyed.  Say what you will about the lack of \r\nmusicianship, but the woman sure does know how to work a crowd.  Fans \r\naround the the edge of the stage were treated to physical contact and the \r\noccasional kiss and hug.  The Mall Queen worked these poor rubes like a \r\nprostitute.  She knew exactly what her pathetic male fans wanted and she \r\ngave it out in spades.\r\n\r\nNostalgia, Celebrity and Thunt.net, powerful forces in today’s consumer \r\ndriven economy.  An aging Mall Queen in spandex pants on a sunny day.  She \r\nclosed the show with “I think we’re alone now”, a song dwarfed by Weird \r\nAl’s brilliant “I think I’m a clone now”.  She looped the chorus about \r\ntwenty times but the crowd didn’t care.  They sang along blindly like \r\nsheep frightened by the sun.  They followed their Mall Queen with blind \r\nfaith, and every where the Mall Queen went, her lambs were sure to go.\r\n', '', 20010307152849, 'normal', '');
INSERT INTO thuntnet_archive VALUES (185, 'Tiffany: The show in photos', 'Thomas Hunt', 'thunt@thunt.net', 'In our continuing coverage of the Tiffany Event, Thunt.net is proud to \r\npresent a collection of photos taken by Thunt.net\'s own star photographer \r\n<b>Matt Brown</b>.  The collection, in it\'s entiretity is available at: \r\n<center><a href=http://thunt.net/thuntphotos/tiffany_matt>\r\nhttp://thunt.net/thuntphotos/tiffany_matt/</a></center>\r\nPlease note that when you click on the thumbnails, you will recieve a full \r\nsized image.  No dedegration of this image has been implemented, and we \r\nask you to enjoy the excellent full size photo.\r\n\r\nHiglights of Matt\'s Photos:\r\n\r\n</pre>\r\n<table>\r\n<tr>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00008.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00008.small.jpg>\r\n</a><br>\r\n<center><b>Welcome to a "Nooner" with Tiffany</b></center><br>\r\n<br>\r\n</td>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00013.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00013.small.jpg>\r\n</a><br>\r\n<center><b>Tiffany!</b></center><br>\r\n<br>\r\n</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00050.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00050.small.jpg>\r\n</a><br>\r\n<center><b>Pound that heart Celine!</b></center><br>\r\n<br>\r\n</td>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00053.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00053.small.jpg>\r\n</a><br>\r\n<center><b>I\'m having a good time.</b></center><br>\r\n<br>\r\n</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00055.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00055.small.jpg>\r\n</a><br>\r\n<center><b>Thunt and Endeen</b></center><br>\r\n<br>\r\n</td>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00059.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00059.small.jpg>\r\n</a><br>\r\n<center><b>Why is that girl crying?</b></center><br>\r\n<br>\r\n</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00064.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00064.small.jpg>\r\n</a><br>\r\n<center><b>Marilyn Manson?</b></center><br>\r\n<br>\r\n</td>\r\n<td>\r\n<a href=http://thunt.net/thuntphotos/tiffany_matt/dsc00065.jpg>\r\n<img src=http://thunt.net/thuntphotos/tiffany_matt/dsc00065.small.jpg>\r\n</a><br>\r\n<center><b>She can write!</b></center><br>\r\n<br>\r\n</td>\r\n</tr>\r\n</table>', '', 20010308195259, 'normal', '');
