INSERT INTO thuntnet_archive VALUES (189, 'My Erotic Linus Torlvalds Dream', 'Shrewm', 'shroom', 'I was in the UCSC library, probably wanting to check my email to stream\r\nsome live porn at speeds only college networks can provide.  As I turned\r\nthe corner and entered one of the computer labs, I noticed him, Linus\r\nTolvalds, in all of his splender and glory dancing in front of a terminal.\r\nI was so shocked and surprised by his presence that I walked right between\r\nhim and his terminal.\r\n\r\nThen he got pissed.  He grunted, walked over to his terminal and type a\r\nfew things.  He then proceeded to do perform his dance all over again.\r\nWhat I didn\'t realize initially, due to my overwhelming feeling of awe and\r\nwarm-fuzziness, was that he was making a video of himself (Obviously to\r\npost on thunt.net) and I messed it up.  I mean, I might as well have asked\r\nhim for his .signature.  I must have been the most annoying user in the\r\nworld to him.\r\n\r\nWell I found an open terminal but realized that below was a shelf that\r\nneeded to be organized so I began to move books and papers around.  Then\r\nit hit me.  A big file.  Then another and another.  I turned around and\r\nnoticed Linus Torvalds, the immortalized GOD to all geeks, throwing random\r\nfiles at me.  He was causing such a clutter that I was having a very\r\ndifficult time organizing the files beneath my workstation.\r\n\r\nThen I woke up.\r\n\r\nNote:  Neither Linus, Me, nor any of the shadowy-like extras in my dream\r\nwere naked.\r\n\r\n', '', 20010312152931, 'normal', '');
