INSERT INTO thuntnet_archive VALUES (288, 'qooutes, qooutes, qooutes', 'Thomas Hunt', 'thunt@thunt.net', 'And now for your entertainment, a selection of real quotes from real \r\npeople.\r\n<BR><BR>\r\n"The Rock is the best movie ever made." – Andy\r\n<BR><BR>\r\n"I plan to quit smoking next week."  -- Ryan Endeen\r\n<BR><BR>\r\n"Dude, did you see that movie Striptease?" – David Sommers\r\n<BR><BR>\r\n"I don\'t do cocaine." – Joe Rodreguiz\r\n<BR><BR>\r\n"J\'ai baisé ma mčre la nuit passée." – Russ\r\n<BR><BR>\r\n"I take it up the ass from Jen Tillet." – Josh Leon\r\n<BR><BR>\r\n"That is so wrong." – Nate\r\n<BR><BR>\r\n"That\'s the sweetest thing.  I got it for five bucks." – Matt Brown\r\n<BR><BR>\r\n"I need sleepy.  Brendan needs sleepy." – Brendan\r\n<BR><BR>\r\n"I hate dat dunt. Man! He dinks he\'s waaay coo\' but he\'s not. Man! Drink \r\nanoda\' beer. Ah be baaad..." – Shara\r\n<BR><BR>\r\n"We have nothing to feaw but feaw itsewf and that waskally wabbit." – \r\nElmer Delano Fudd.\r\n<BR><BR>\r\n"I\'m goigg back t\' de hornet. I\'ll be dehe in fibe minoots. Dude, uh uh \r\nuh, chill the, uh uh uh, fuck out, GEEEHEEHEEE. I\'m commigg." – Andy\r\n<BR><BR>\r\n"I got lost in borders. I \'ave no cheese. I wish I \'ad a Michael Caine so \r\nI could ball of chalk in a straight line." – Art Pimentale<BR><BR>\r\n"I\'m zee Ideetur in Cheeeff. Thet meuns I\'m in cherge-a. Foock Undy, he\'s \r\na poony leettle-a beetch. Iff yuoo luuk et my peectoores, I veell sooe-a \r\nyuu. Hurty flurty schnipp schnipp! Dun\'t meke-a foon ooff my ugly teet." – \r\nLaylaLand\r\n<BR><BR>\r\n\r\n\r\n', '', 20010924165112, 'normal', '');
