INSERT INTO thuntnet_archive VALUES (295, 'This is how I feel', 'Thomas Hunt', 'thunt@thunt.net', 'Longview [<a href="http://thunt.net/mp3/04- Longview.mp3">listen</a>], a song by Green Day<br>\r\n<br>\r\nSit around and watch the tube but nothing\'s on <BR>\r\nI change the channel for an hour or two <br>\r\nTwiddle my thumb just for a bit <BR>\r\nI\'m sick of all the same old shit <BR>\r\nIn a house with unlocked doors <BR>\r\nAnd I\'m fucking lazy <BR>\r\n<BR>\r\nBite my lip and close my eyes <BR>\r\nTake me away to paradise <BR>\r\nI\'m so damn bored I\'m going to blind!!! <BR>\r\nAnd I smell like shit <BR>\r\n<BR>\r\nPeel me off from this velcro seat and get me moving <BR>\r\nI sure as hell can\'t do it by myself <BR>\r\nI\'m feeling like a dog in heat <BR>\r\nBarred indoors from the summer street <BR>\r\nI lock the door to my own cell <BR>\r\nAnd I lost the key <BR>\r\n<BR>\r\nBite my lip and close my eyes <BR>\r\nTake me away to paradise <BR>\r\nI\'m so damn bored and I\'m going to blind <BR>\r\nAnd I smell like shit <BR>\r\n<BR>\r\nI got no motivation <BR>\r\nWhere is my motivation <BR>\r\nNo time for motivation <BR>\r\nSmoking my inspiration <BR>\r\n<BR>\r\nI sit around and watch the phone but no one\'s calling <BR>\r\nCall me pathetic, call me what you will <BR>\r\nMy mother says to get a job <BR>\r\nBut she don\'t like the one she\'s got <BR>\r\nWhen masturbations lost its fun <BR>\r\nYou\'re fucking lazy<BR>\r\n<BR>\r\nBite my lip and close my eyes <BR>\r\nTake me away to paradise <BR>\r\nI\'m so damn bored and I\'m going to blind <BR>\r\nAnd lonliness has to suffice <BR>\r\nBite my lip and close my eyes <BR>\r\nSlipping away to paradise <BR>\r\nSome say quit or I\'ll go blind<BR> \r\nBut it\'s just a myth <BR>\r\n<BR>', '', 20011005130151, 'normal', '');
INSERT INTO thuntnet_archive VALUES (296, 'Bin Laden\'s Hideous Plot', 'Thomas Hunt', 'thunt@thunt.net', '<B>Inspired by John Humphreys<br>\r\n<I>in the style of <a href=http://stratfor.com>stratfor</a></i><br>\r\n1700 GMT, 011017</B><br>\r\n<br>\r\n<B>Summary</B><br>\r\n<br>\r\nDue to the restrictions placed upon known terrorist Osama Bin Laden\'s bank \r\naccounts, his financial situation has become unsound.  These restrictions, \r\nas well as the discovery and failure of his post-Sept. 11th stock market \r\nswindle has left him with no choice but to seek an alternative form of \r\nfunding.  Thus he has turned to the lucrative field of sports gambling. \r\n<br>\r\n<br>\r\n<B>Analysis</B><br>\r\n<br>\r\nThe New York Yankees, the so-called America\'s team was obviously not a \r\ngood bet before the Sept. 11th tragedy, but afterwards, the political \r\nsymbolism of America\'s Team cannot be overlooked.  <br>\r\n<br>\r\nDespite their natural skill and now "holy" quest, the Yankees began their \r\npost season by trailing in the ALDS series two games to zero and were in \r\ngrave danger of being eliminated by the non-politically charged Oakland \r\nAthletics.  It is now that we see Bin Laden\'s organization take action.  \r\n<br>\r\n<br>\r\nUsing his cash resources, Laden was able to purchase one or several \r\nplayers on the Oakland team, and in a fashion befitting the classic 1919 \r\nWhite Sox team, the A\'s were persuaded to throw the series.  The A\'s were \r\nan easy target for bribery as most of their players are rookies and thus \r\nincredibly underpaid.  The Yankees, on the other hand would be incredibly \r\ndifficult to bribe as their players are all incredibly overpaid.  Due to \r\nOsama\'s work, the Yankees miraculously came from behind to defeat the A\'s \r\nin three straight games.  America was overjoyed, but unfortunately Bin \r\nLaden had doubled and perhaps tripled his bets when the Yankees were \r\ntrailing and profited greatly from the victory of America\'s Team. <br>\r\n<br>\r\nNo doubt Bin Laden and the Yankees will continue their disastrous and \r\ndangerous winning streak all the way to the World Series.  It is at the \r\nWorld Series that the dual nature of Bin Laden\'s plan will become known.  \r\nWith his now restored cash flow, Laden will no doubt attempt to wash away \r\nthe evidence of America\'s Team.  If America and the Major League Baseball \r\norganization does not take steps to stop this tragedy, by overturning the \r\nALDS series, both America and the Yankees will no doubt reap the \r\nwhirlwind. <br>\r\n', '', 20011017144234, 'normal', '');
INSERT INTO thuntnet_photo VALUES (10, '2000/rexs_wedding', 'Some photos I shot at Rex\'s wedding.  There are some nice ones of me in a \r\nTuxcedo, shot by <a href=http://ismedia.org>Nate</a>.', 20010305161218, 'Rex\'s Wedding');
INSERT INTO thuntnet_photo VALUES (6, '2001/05-00-01_-_roll01', 'Roll #1 was an experiment.  I found a roll of film in my desk and I \r\ndecided to shoot a roll.  It actually turned out pretty good and also \r\nserves as a decent photo record of a day or two in my life.', 20010407125558, 'Roll #1');
INSERT INTO thuntnet_photo VALUES (7, '2001/04-00-01_-_easter', 'My brother wasn\'t able to spend Easter with the family and some other \r\nmembers of the family spent Easter in Fresno, so I put up some photos of \r\nmy Mother, my Father and I making and enjoying Easter dinner.', 20010415125655, 'Easter 2001');
INSERT INTO thuntnet_photo VALUES (8, '2001/05-00-01_-_voting_ecs', 'As a parody/homage to the movie Election, I had my good friend Josh take \r\npictures of my while I was voting in the ASI election.  The really fun \r\nshots are where you can actually see who I\'m voting for.', 20010508125806, 'ASI Voting 2001');
INSERT INTO thuntnet_photo VALUES (13, '2001/06-00-01_-_thunt_apartment_03', 'These are photos of my third apartment.  It was a nice apartment because \r\nof the rent and the location.  A mere $550 a month, split between myself \r\nand my roommate Matt.  And only five minutes from school.  Quite a find.', 20010507161827, 'Thunt\'s Third Apartment');
INSERT INTO thuntnet_photo VALUES (12, '2000/rexs_wedding_pro', 'These are photos of Rex\'s Wedding taken by a proffessional photographer.  \r\nHe\'s pretty good.  I especially enjoyed the edges he did on some of the \r\nblack and white shots and when he lay on the floor with a fish-eye lens \r\nand had the entire wedding party crowd around him and look down.  The look \r\non the ring bearer\'s face is absolutely priceless.', 20010303161535, 'Rex\'s Wedding - Pro');
INSERT INTO thuntnet_photo VALUES (14, '2001/03-00-01_-_tiffany_matt', 'Photos taken by <a href="http://mattbrown.com">Matt Brown</a> of Thunt, \r\nAndy, Endean and more enjoying the shitty sounds of Tiffany...', 20010401164455, 'Tiffany Concert @ CSUS');
INSERT INTO thuntnet_photo VALUES (15, '2000/portfolio', 'Thunt shot, developed and printed the following photos for his \r\nbegining black and white photography class during the spring of year 2000. \r\nHis proffessor described his work as "very strong technically", "a \r\nsimplicity  to subject matter that is very pleasing" and "an excellent job \r\nof showing mundane objects in a graphic and intersting way"', 20001102164547, 'Portfolio');
INSERT INTO thuntnet_photo VALUES (16, '2000/other', 'Outtakes & Omissions from Thunt\'s Photo40 class.', 20001101164652, 'Potfolio B-Sides');
INSERT INTO thuntnet_photo VALUES (17, '2001/05-00-01_-_fire', 'There was a major fire across the street from my apartment complex.  \r\nPhotos by Matt Brown.', 20010519104509, 'The fire of May 19, 2001');
INSERT INTO thuntnet_photo VALUES (18, '2001/06-04-01_-_vacaville', 'My brother Adam took these excellent pictures highlighting our Palatial \r\nVacaville Estate.  Check out the pool, it\'s cool!', 20010628124536, 'Palatial Vacaville Estate');
INSERT INTO thuntnet_photo VALUES (19, '2001/06-03-01_-_smokey', 'These are some pictures of my cat, Smokey.', 20010628124933, 'Smokey the Cat');
INSERT INTO thuntnet_photo VALUES (26, '2001/06-28-01_-_portland2', 'More pics from Oregon.  Sweeet.', 20010629070454, 'Portland, OR part II');
INSERT INTO thuntnet_photo VALUES (27, '2001/06-28-01_-_portland3', 'Still more pictures from Thunt\'s epic adventure to Portland, Oregon.', 20010720111921, 'Portland, OR part III');
INSERT INTO thuntnet_photo VALUES (21, '2001/06-00-01_-_frog_attack', 'A frog wandered into our palatial Vacaville estate, fortunately we were \r\nable to capture it with a pool net and a cookie sheet, and release it into \r\nthe wild where it will go on to do more damage.  Please note the frog is \r\nnext to the DVD player.  In some pictures, you can\'t see it too well, you \r\nkindof have to look for it like Where\'s Waldo.', 20010628125229, 'Frog Attack!');
INSERT INTO thuntnet_photo VALUES (22, '2001/06-01-01_-_labbie_picnic', 'Here are some pictures of my friends, at the Labbie (lab assistant) \r\npicnic.  Pretty exciting stuff.', 20010628125348, 'Labbie Picnic');
INSERT INTO thuntnet_photo VALUES (23, '2001/06-05-01_-_andy_party', 'Mike and I went over to Andy\'s, one Monday night and a quasi-party \r\nformed...  This is the night-time part, featuring one quasi-drunk Josh \r\nLeon.', 20010628125556, 'Andy Party');
INSERT INTO thuntnet_photo VALUES (24, '2001/06-06-01_-_andy_party2', 'Mike and I went over to Andy\'s, one Monday night and a quasi-party \r\nformed...  This is the day-time part, featuring Andrea, wardrobe by <a \r\nhref=http://transgressboarding.com>Transgress boarding co</a>.', 20010628125645, 'Andy Party part II');
INSERT INTO thuntnet_photo VALUES (25, '2001/06-26-01_-_portland', 'This is the first batch of pictures from Portland.  Featuring Phil\'s \r\nAmerican Psycho Apartment, with B&W speakers and a mad-fat Krell CD \r\nplayer, among other refinements.  Also featured: Wacker Corporation and of \r\ncourse Phil.', 20010628125937, 'Portland, OR part I');
INSERT INTO thuntnet_photo VALUES (28, '2001/06-29-01_-_seatle', 'Thunt and Phil explore the wilderness of Seattle.  Tons of really cool \r\npictures including the Thunt+SpaceNeedle Series, the "CHOWN" sign, \r\nwww.800.com and cigars.', 20010720112106, 'Seattle');
