INSERT INTO thuntnet_photo VALUES (31, '2001/07-10-01_-_sepia', 'Fun with filters.  Thunt plays with the new camera around the house \r\nshooting old timey style.', 20010720112456, 'Sepia Pictures');
INSERT INTO thuntnet_photo VALUES (32, '2001/07-14-01_-_wedding', 'My cousin John got married recently.  It was an excellent wedding because \r\nI got to wear shorts and a hawaian shirt.', 20010720112645, 'My cousin John\'s wedding');
INSERT INTO thuntnet_photo VALUES (33, '2001/07-29-01_-_travel_utah', 'Experience life on the road with Thunt, as he travels to Utah.', 20010803113440, 'Traveling to Utah');
