INSERT INTO thuntnet_photo VALUES (35, '2001/07-30-01_-_joes', 'Ever wonder how a student at BYU lives?  Come with Thunt as we go on a \r\nprivate tour of Joe\'s Apartment in Provo, UT.', 20010803113607, 'Joe\'s Apartment');
INSERT INTO thuntnet_photo VALUES (36, '2001/07-30-01_-_salt_lake', 'Thunt, Joe and Mike go on an epic adventure to Salt Lake.  They witness \r\nmany things, including an incredible auditorium that has no pillars so all \r\ncan see, a church with wild west writing on the side of it and much much \r\nmore.', 20010803113701, 'Journey to Salt Lake');
INSERT INTO thuntnet_photo VALUES (37, '2001/07-31-01_-_travel_co', 'Thunt crosses Utah and Wyoming on his way to colorado.  Experience the \r\nbeauty of absence.', 20010803113751, 'Traveling to Colorado');
