INSERT INTO thuntnet_photo VALUES (39, '2001/05-00-01_-_mikes_camera', 'This is a collection of photos I shot with Mike\'s camera around the ECS \r\nand Engineering buildings.', 20010506172907, 'photos shot with mike\'s camera');
INSERT INTO thuntnet_photo VALUES (40, '2001/06-00-01_-_graduation', 'A collection of photos from my graduation.  Mostly of the party and my \r\nrelatives.', 20010606174338, 'Graduation');
INSERT INTO thuntnet_photo VALUES (41, '2001/08-02-01_-_colorado', 'Rain, sun and thunt in a white t-shirt using his laptop.  Live the \r\nexcitement of colorful colorado!', 20010806194816, 'Colorado');
