INSERT INTO thuntnet_photo VALUES (44, '2001/08-05-01_-_devilstower_rushmore', 'Thunt and Ben travel to the ends of Wyoming to Devil\'s Tower and deep into \r\nSouth Dakota to see Mt. Rushmore.', 20010806195013, 'Devil\'s Tower & Rushmore');
INSERT INTO thuntnet_photo VALUES (45, '2001/08-11-01_-_bens', 'See Ft. Collins the way Thunt saw it, living in Ben\'s apartment.  (Special \r\nAppearance by Ben!)', 20010816161319, 'A tour of Ben\'s Apartment');
INSERT INTO thuntnet_photo VALUES (46, '2001/08-11-01_-_rockymountains', 'Big mountains, and a lot of them.  Join Thunt and Ben as they tour the \r\nRockies.', 20010816161404, 'Rocky Mountains');
