INSERT INTO thuntnet_photo VALUES (48, '2001/08-12-01_-_travel_wy', 'Thunt returns to Utah, passing once more through the phantom state that is \r\nWyoming.', 20010816161546, 'Traveling back to Utah');
INSERT INTO thuntnet_photo VALUES (49, '2001/09-09-01_-_josh_leon_party', 'I came, I saw, I took photos of Josh Leon getting beat up by girls.  Sorry \r\nabout all the fucking "red eye" photos.  I gotta remember to turn on the \r\nno "red eye" thing next time.  ', 20010909053337, 'Josh Leon\'s Party');
INSERT INTO thuntnet_photo VALUES (50, '2001/08-21-01_-_more_fireworks/', 'A couple of nice fireworks shots from the California State Fair.', 20010821110926, 'More Fireworks');
INSERT INTO thuntnet_photo VALUES (51, '2001/08-24-01_-_motel_chowchilla/', 'I just think this sign says all that needs to be said about Chowchilla.', 20010824111042, 'Motel Chowchilla');
INSERT INTO thuntnet_photo VALUES (52, '2001/08-25-01_-_justins_wedding/', 'A wedding, in Chowchilla.', 20010825111119, 'Justin and Jennifer\'s Wedding');
INSERT INTO thuntnet_photo VALUES (53, '2001/09-11-01_-_TNCC', 'Housed at a secret location in Vacaville, California, the Thunt.Net \r\nCommand Center (TNCC) is prepared to handle any disaster, man-made or \r\notherwise.', 20010911210954, 'Thunt.Net Command Center');
INSERT INTO thuntnet_photo VALUES (54, '2001/09-11-01_-_terrorist_bombing', 'Director Keenan gathered these pictures from across the internet to give \r\nyou a better view of the disaster at the World Trade Center.  \r\n(Highlights:  A car with the word war written in the dust, an album cover \r\nfrom before the disaster with the buildings exploding in the background)', 20010911223858, 'Terrorist Bombing Photos');
INSERT INTO thuntnet_photo VALUES (55, '2001/09-12-01_-_mobile_command', 'Thunt.net goes on the road to Sacramento to reach high speed internet \r\naccess to better cover the story.  Experience the glory of Thunt.net - \r\nMobile Command.', 20010912023603, 'Thunt.Net Mobile Command');
INSERT INTO thuntnet_photo VALUES (56, '2001/09-12-01_-_battleship', 'FBI Director Humphreys vs. Mexican Ambassador Humphreys.  A grudge match \r\nof epic proportions.', 20010913175037, 'TMCC: Battleship');
INSERT INTO thuntnet_photo VALUES (57, '2001/09-13-01_-_scrabble', 'Équipage De Thunt plays Scrabble instead of destroying Codename Nice \r\nAss?\'s party?  Could these photos be real?  Could they be from the hours \r\nof 10:00 pm until 2:00 am?', 20010915185707, 'Équipage De Thunt: Scrabble');
INSERT INTO thuntnet_photo VALUES (58, '2001/10-13-01-adams_in_chico', 'The whole family travels out to Chico to visit Adam at college.  A good time had by all.', 20011201124211, 'My Brother Adam\'s Apartment in Chico');
