INSERT INTO thuntnet_reviews VALUES (1, 'Object of My Affection, The', '1998', 'Chasing Amy, reversed. Aniston falls in love with a \r\ngay guy. Mildly interesting plot twist, she\'s \r\npregnant, they\'re going to raise the baby together...  ', 'Bleck. Imagine a guy who doesn\'t want to sleep with \r\nJennifer Aniston. Acting, bleck. Story, bleck. Goes on \r\nforever, about 4 endings tacked on the thing. Alan \r\nAlda great however, as usual, but nothing spectacular. ', '2', 'Nicholas Hytner', 'movies', 20011006115013);
INSERT INTO thuntnet_reviews VALUES (2, 'Ghost in the Shell', '1995', 'Humans, cyborgs, the future. Plot deals with AI & \r\nConsciousness. Do the cyborgs have souls? Follows the \r\ntrail of a few cyborg cops from Section 9. Film is \r\nJapanese Animation.  ', 'A good film. Lots of good chase scenes, fighting and \r\ntypically with Japanese animation: large breasted \r\nfemale nudity, which is good. The film is an obvious \r\nprecursor and inspiration for the matrix.  ', '3', 'Mamoru Oshii', 'movies', 20011006115124);
INSERT INTO thuntnet_reviews VALUES (3, 'Legend of Bagger Vance, The', '2000', 'Matt Damon, a golfer returns from WWI with a broken \r\nspirit. Will Smith (Bagger Vance), a black caddy, \r\nJesus/God type figure appears and helps Damon regain \r\nhis game. Because after all, golf is life? ', 'Typical Redford. Epic, lots of nature shots. Theron\'s \r\naccent is sketchy, and she doesn\'t get naked. Damon is \r\nadequate, but John complained constantly of his lousy \r\ngolf swing. It\'s strange to see a period piece during \r\nprohibition where they drink so much. Bad history, and \r\ntypical.<BR> <BR> Film goes on forever. Drags on, I \r\nshould say. Lousy attempt to recapure the glory of The \r\nNatural.  ', '2', 'Robert Redford', 'movies', 20011006115233);
INSERT INTO thuntnet_reviews VALUES (4, 'Absence of Malice', '1981', 'Paul Newman plays a son of a mobster who is being \r\ninvesigated in the disaperance of another mobster. The \r\nkicker is he\'s only being investigated because the \r\nfeds are trying to get him to help them find the \r\nkiller. They\'re using Sally Field, a newspaper \r\nreporter to publish the info ', 'Mildly interesting. Newman sets up the feds pretty \r\ngood and has sex with Gigdet (Sally Field), also he \r\nshows anger and slaps her around a bit following the \r\nsuicide of his friend that she caused.<BR> <BR> I \r\nwatched it because I borrowed a bunch of videos from \r\nmy Mother.  ', '3', 'Syndey Pollack', 'movies', 20011006115425);
INSERT INTO thuntnet_reviews VALUES (5, 'Speechless', '1994', 'Based on James Carville and Mary Madson, two speech \r\nwriters, one republican, one democrat, fight, fuck and \r\nfall in love. ', 'I like this movie. Starring Michael Keaton (Batman, \r\ncool) and Geena Davis (hot) it\'s fun to watch over and \r\nover again. I like how the speeches they write attack \r\neach other and how they fight over the spin.   ', '3', 'Ron Underwood', 'movies', 20011006115540);
INSERT INTO thuntnet_reviews VALUES (6, 'House of Yes, The', '1997', 'Parker Posey plays an insane woman who has a serious \r\nJackie-O obsession. Her brother returns home with a \r\nfinace and leaves in pine box.  ', 'Funny at times, but mostly disturbing. I like Posey \r\nand as usual she\'s great. It\'s well written, but it \r\nwas a play and feels very much like a play, rapid fire \r\ndialogue. Worth watching, but not worth running out \r\nfor. ', '3', 'Mark S. Waters', 'movies', 20011006115628);
INSERT INTO thuntnet_reviews VALUES (7, 'AntiTrust', '2001', 'A Bill Gates character is triumphing in the software \r\nmarket by stealing code from kids in garages and \r\noccasionally killing them. But it all goes wrong when \r\na young silly programmer double crosses him. ', 'Pure shit. Bad plot. Bad technical stuff. Laughable. \r\nAttempts to mimic hitchcock at points and fails. \r\nAttempts to be suspenceful and fails. Attempts to be \r\nfunny and fails. Do not see, even computer geeks who \r\nlike to laugh at geek films won\'t like this one. ', '1', 'Peter Howitt (II)', 'movies', 20011006115737);
INSERT INTO thuntnet_reviews VALUES (8, 'Story of Us, The', '1999', 'A married couple on the rocks. Will they split or not. \r\nDo they have a history? Are they an us? Who gives a \r\nfuck? ', 'Lousy movie by Reiner. Tries to be Woody Allen and \r\nfails. Willis is ok, Pfeiffer is crappy, she looks \r\nlike a poltergiest with tits. You never really care \r\nabout the characters and I don\'t believe the ending. \r\nWhen people are sick of eachother they split. And \r\nthat\'s that.', '2', 'Rob Reiner', 'movies', 20011006115841);
INSERT INTO thuntnet_reviews VALUES (9, 'Shrek', '2001', 'An ogre rescues a princess and they fall in love.  ', 'Funny at parts. Fart jokes at others. Animation is \r\nbreath- taking but seems to distract from story. \r\nVoices are good. Jokes at the expense of Fairy tale \r\ncharacters are better. Possible negative stereotype by \r\nEddie Murphy playing the donkey, speaking in black \r\ntone, or perhaps just Eddie Murphy speak. ', '3', 'Andrew Adamson', 'movies', 20011006115928);
INSERT INTO thuntnet_reviews VALUES (10, 'Little Nicky', '2000', 'The devil\'s son returns to earth to stop the other \r\ndevil\'s sons from causing the devil to die. And he \r\nfalls in love. ', 'Pure shit. This movie is not funny and all of the \r\ncharacters voices and actions piss me off. Jokes fail \r\nthroughout. A guy with boobs on his head. His mother \r\nis an angel (the beautiful Reece Witherspoon), HA! \r\nFilled with stars, Keitel, Tarantino, Carvey, etc, but \r\nfilled with shit. This movie was worse than Driven, \r\nbut better than How Stella got her Groove back.', '1', 'Steven Brill', 'movies', 20011006120031);
INSERT INTO thuntnet_reviews VALUES (11, 'Bounce', '2000', 'A guy dies on a plane crash with someone else\'s \r\nticket. Someone else feels bad about it and goes and \r\nfucks, falls in love with that dead guy\'s wife.', 'Crappy. Affleck, boring. Paltrow, ugly brown hair. Un- \r\ninteresting. Best part: The begining when Affleck, a \r\nplayer, skips his plane to have a lay-over with that \r\nhot chick from Con Air. It goes downhill from there. ', '2', 'Don Roos', 'movies', 20011006120122);
INSERT INTO thuntnet_reviews VALUES (12, 'Dial \'M\' for Murder', '1954', 'A man wants his wife dead. He blackmailes another man \r\nto do it, but everything goes wrong. ', 'Starring the beautiful Grace Kelly, this is not one of \r\nHitchcock\'s best, but it\'s pretty great. Suspenceful \r\nand interesting, I rooted for the bad guy, but \r\nregreted his vendetta against the stunning Grace \r\nKelly. But she looks better in Rear Window. ', '3', 'Alfred Hitchcock', 'movies', 20011006120206);
INSERT INTO thuntnet_reviews VALUES (13, 'Party Girl', '1995', 'A young Party Girl grows up and gets a job without \r\nloosing her party roots.  ', 'Parker Posey is stunning. Beautiful and a good actor. \r\nThis indy flick isn\'t as good as The Party with Peter \r\nSellers but it\'s better than Valley Girl with Nick \r\nCage. The lines are great, the plot is sketchy and the \r\nstory drags, but Posey is awesome and makes the film \r\nfun and worth seeing. ', '3', 'Daisy von Scherler Mayer', 'movies', 20011006120317);
INSERT INTO thuntnet_reviews VALUES (14, 'Driven', '2001', 'A young driver needs help from an old driver to be all \r\nhe can be. ', 'Pure shit. Made for people with ADD. Storylines are \r\ndropped and picked up in naration. The movie runs and \r\nruns, occasionally stopping for a shitty speech by \r\nBurt Renolds. Ripped off from Days of Thunder, Top Gun \r\nand many others, this Stallone written and starring \r\npic, sucks dick. ', '1', 'Renny Harlin', 'movies', 20011006120356);
INSERT INTO thuntnet_reviews VALUES (16, 'Basketball Diaries, The', '', 'A story about the streets of New York.  Mainly \r\nfeatures a young man\\\'s journey through basketball, \r\ndrugs and sex.', 'Excellent book.  Beautiful but simple language.  \r\nSimilar to The Catcher in the Rye.  ', '4', 'Jim Carroll', 'books', 20011026233904);
INSERT INTO thuntnet_reviews VALUES (17, 'Secrets and Lies: Digital Security in a Networked World', '', 'Non Fiction.  Schneider details the ins and outs of \r\ncomputer security.  Highlights: The Chapter on Users \r\nis hilarious, and the opening in which Schneider \r\nadmits that total security is impossible due to the \r\nstupidity of users.', 'Great book.  Nice overview of security.  Not too \r\ntechnical, but still informatative.', '3', 'Bruce Schneider', 'books', 20011026234145);
INSERT INTO thuntnet_reviews VALUES (18, 'Easy Riders, Raging Bulls: How the sex-drugs-and-rock\\\'n\\\'roll generation saved hollywood', '', 'Non Fiction.  An excellent account of Hollywood\\\'s \r\nrising directors of the 1970s and how they failed.', 'Good book. Fun facts about your favorite directors.  A \r\ncrazy book about a crazy time when Hollywood made \r\ngreat movies and ground breaking directors did drugs \r\nand made movies.  ', '3', 'Peter Biskind', 'books', 20011026234548);
INSERT INTO thuntnet_reviews VALUES (19, 'Bright Lights, Big City', '', 'An un-named character (you) journeys through \r\ndepression in New York City.  Through sex and \r\njoblessness, love and despair.  Similar to The Catcher \r\nin the Rye.  Side note:  Great supporting character \r\nnamed Tad Allagash (the Allagasher), notoriously late, \r\ncares for no one, constantly the life of the party, \r\nworth reading for him alone.', 'Great book, similar but inferior to The Catcher in the \r\nRye.  I liked it a lot though.  I think I\\\'ll re-read \r\nit sometime just to catch up on the adventures of a \r\nside character named Tad Allagash (the Allagasher).', '3', 'Jay McInerney', 'books', 20011026234955);
INSERT INTO thuntnet_reviews VALUES (20, 'Fight Club', '', 'A man who can\\\'t sleep becomes addicted to self help \r\ngroups, then starts one of his own: Fight Club.  You \r\nknow the plot, you watched the movie.', 'Great book.  Awesome counter-yuppie culture shock type \r\nlanguage.  Attacks the core values of our Starbucks \r\ndominated society.  Quick style, agressive language, \r\ngood read.', '4', 'Chuck Palahniuk', 'books', 20011026235237);
INSERT INTO thuntnet_reviews VALUES (21, 'Invisible Monsters', '', 'A fashion model goes a bit whacked.  Interesting plot \r\ntwists and a TYPICAL PALAHNIUK suprise ending.', 'A good book, nice language, but Palaniuk fails on the \r\nending.', '3', 'Chuck Palahniuk', 'books', 20011026235509);
INSERT INTO thuntnet_reviews VALUES (22, 'Survivor : A Novel', '', 'A refugee from a religious cult starts a suicide \r\npromotion hotline.  Twists and turns, then a SUPRISE \r\nENDING.', 'Good book, fun to read, but typical Palahniuk.', '3', 'Chuck Palahniuk', 'books', 20011026235622);
INSERT INTO thuntnet_reviews VALUES (23, 'On Writing', '', 'Non Fiction.  King discusses how he writes, why he \r\nwrites and touches on the time he got run over by a \r\ncar.', 'Good read, very informatative, but King\\\'s ability to \r\nconstantly turn out novels is a bit depressing to us \r\nnormal people.', '3', 'Stephen King', 'books', 20011026235849);
INSERT INTO thuntnet_reviews VALUES (24, 'Even Cowgirls get the Blues', '', 'The story of a female hitchhiker.  A woman with \r\nextraordinary thumbs.  The tale of a cowgirl and her \r\nranch.  Attempting to describe the plot of a Tom \r\nRobbins book is like trying to explain the \r\nconstitution to a crack addict while balancing an \r\nelephant on top of your left index finger.', 'Wild and crazy.  Plot turns, twists, and a cameo by \r\nthe author.  All the madness you\\\'ve come to expect \r\nfrom Robbins and a few references to Jack Kerouac, not \r\nbad, not bad at all.', '3', 'Tom Robbins', 'books', 20011027000206);
INSERT INTO thuntnet_reviews VALUES (25, 'Carrie', '', 'A young girl is made fun of, until she develops \r\nsupernatural powers and kicks everyones fucking ass.', 'An explosion of power for a young writer (King\\\'s first \r\npublished work).  Nice narrative structure of reveals \r\nsimilar to Capote\\\'s In Cold Blood.  The mix of mock \r\nnewspaper and magazine articles also gives the book \r\na \\"non fiction\\" feeling.  Worth reading.', '3', 'Stephen King', 'books', 20011027000341);
INSERT INTO thuntnet_reviews VALUES (26, ' Faust', '', 'A man sells his soul to the devil.  Obviously a \r\nmistake.', 'It\\\'s important to read the classics.  I had a far \r\nsimplier idea of the Faust story before I read this \r\nand I exited knowing that the real story is very \r\ncomplex and very interesting.', '3', 'Goethe', 'books', 20011027000542);
INSERT INTO thuntnet_reviews VALUES (27, 'Riding the Rap', '', 'A cop tracks down a killer or something.  ', 'More brain candy from Elmore Leonard.  I read it on an \r\nairplane, as I always read Elmore Leonard books on \r\nairplanes.  Good characters, lots of crime, starts up \r\nyour appetite but doesn\\\'t bring it back down.', '3', 'Elmore Leonard', 'books', 20011027000755);
INSERT INTO thuntnet_reviews VALUES (28, 'Another Roadside Attraction', '', 'The mummfied body of Christ is found and set up in a \r\nroadside circus.  So much more than just another \r\nroadside attraction.', 'More madness from Robbins.  Great characters, great \r\nplot twists, worth reading.', '3', 'Tom Robbins', 'books', 20011027000906);
INSERT INTO thuntnet_reviews VALUES (29, 'Timequake', '', 'A mix between fiction and non fiction.  A timequake \r\noccurs, making the world repeat, but then the \r\ntimequake ends and the world awakes.  Kilgore Trout is \r\nneeded to make them wake up.', 'Vonnegut\\\'s self proclaimed last novel.  A bit \r\ndepressing as he mixes in personal details and \r\ndelivers a well written goodbye.  So it goes.', '3', 'Kurt Vonnegut', 'books', 20011027001150);
INSERT INTO thuntnet_reviews VALUES (30, 'Queer', '', 'While taking some time off from heroin, Bill Lee \r\n(burroughs) discovers his sex drive and has a serious \r\nof not so great affairs with men in Mexico.', 'This book is true.  I would prefer if Burroughs had \r\nmanaged to use his real name as he did in Junky, but I \r\nadmire him greatly for having the courage what is so \r\nobviously his deeply personal longings in a book for \r\nall to see.', '3', 'William S. Burroughs', 'books', 20011027001438);
INSERT INTO thuntnet_reviews VALUES (31, 'Junky', '', 'A man develops a habit.  A habit for heroin.', 'Brilliant.  The truth about what it\\\'s like to be a \r\njunky from a junky.  Burroughs pours his heart out on \r\nthe pages and pages glow, as they always do when it\\\'s \r\nthe truth.', '4', 'William S. Burroughs', 'books', 20011027001624);
INSERT INTO thuntnet_reviews VALUES (32, 'The Sun also Rises', '', 'A crew of misfits visit Pampaloma for some \r\nbullfighting action.', 'Beautiful.', '4', 'Ernest Hemingway', 'books', 20011027001836);
INSERT INTO thuntnet_reviews VALUES (33, 'Proof of Life', '', 'A man (Dennis Quad) is kidnapped.  A proffessional \r\nnegoatior is sent to negoiate for his release.  He \r\nfalls in love with the man\\\'s wife (Meg Ryan).', 'Interesting look at negoiation.  Russell Crowe is \r\ngreat.  I\\\'ll be he was also great fucking Meg Ryan, \r\nhis married co-star of the picture. hehehe.', '3', '', 'movies', 20011027003048);
INSERT INTO thuntnet_reviews VALUES (34, 'The Family Man', '', 'Have you seen It\\\'s a Wonderful Life?  It\\\'s pretty much \r\nthe same thing.', 'Ehhh.  Not bad, but not good either.  Cage is not \r\nreally likable (when compaired to Jimmy Stewart).  \r\nLeone is hot.  ', '3', '', 'movies', 20011027003329);
INSERT INTO thuntnet_reviews VALUES (35, 'Save the last dance', '', 'A white girl in the ghetto falls in love with a black \r\nguy.  She also learns how to hip hop dance and uses \r\nher new found ghetto-sense to win a ballet scholarship.', 'Lousy, boring and predictable.  Stiles is hot though.', '2', '', 'movies', 20011027003454);
INSERT INTO thuntnet_reviews VALUES (36, 'Girl Interupted', '', 'A girl pretends to be a boy.  Later killed by \r\nrednecks.  Based on a true story.', 'Good film.  The kind that you should see but you\\\'ll \r\nnever really find enjoyable.  Hillary Swank is awesome \r\nas the woman/man, if you\\\'re into that sort of thing.', '3', '', 'movies', 20011027003617);
INSERT INTO thuntnet_reviews VALUES (37, 'Saving Silverman', '', 'An idiot is getting married to a woman who is bad for \r\nhim.  His friends try to save him by kidnapping his \r\nfiance.', 'Funny but not hilarious.  It does have Jack Black \r\nthough, who is very funny.  Far too much Neil Diamond \r\nthough.  ', '3', '', 'movies', 20011027003854);
INSERT INTO thuntnet_reviews VALUES (38, 'Sugar and Spice', '', 'Idiotic cheerleaders decide to rob a bank.', 'Tries to be poignant, tries to be funny, tries to be a \r\ngood movie but is a total pile of shit.  Even hot \r\nchicks in cheerleader costumes fail to raise the mark \r\non this pile of shit.  The narrative style is full of \r\nannoying voiceover, too.', '2', '', 'movies', 20011027004019);
INSERT INTO thuntnet_reviews VALUES (39, 'Bait', '', 'A black ex-con is used as bait for a \\"genius\\" thief.', 'The only good thing about this movie is Jaimee Fox, \r\nhe\\\'s kinda funny and I\\\'m glad he got the part in Any \r\nGiven Sunday (a far better movie btw).  The film \r\ndrags, fails to decide between drama and comedy and \r\nalso fails to supply a decent ammount of action.', '2', '', 'movies', 20011027004257);
INSERT INTO thuntnet_reviews VALUES (40, 'Outbreak', '', 'A bad monkey spreads a bad virus.  The world\\\'s only \r\nhope is a rouge scientist named Rainman.', 'Good movie.  All too real with the recent (2001) \r\nantrhax scares.  I still can\\\'t get over Hoffman being \r\nanything but Rainman and I have a hard time believing \r\nhim as a world saving doctor.  The secret government \r\nconspiracy plot line (starring Sutherland and Freeman) \r\nis a bit hard to swallow though.  And the ending is a \r\nbit mellodramatic.', '3', '', 'movies', 20011027004548);
INSERT INTO thuntnet_reviews VALUES (41, 'The Hustler', '', 'A pool shark gets on a bad streak, falls in love, gets \r\non a hot streak and his girl kills herself.', 'Great picture.  Newman and Scott explode in their \r\nperformances.  Drags in parts, but overall worth \r\nwatching.', '3', '', 'movies', 20011027004750);
INSERT INTO thuntnet_reviews VALUES (42, 'The day of the jackel', '', 'The President of France is to be assassinated by The \r\nJackel.  Dramatic game of cat and mouse.  Unfortuately \r\nthe cop succeeds and the Jackel fails, but it\\\'s \r\nexciting.', 'Dramatic cat and mouse chase.  Exciting.  Worth seeing.', '3', '', 'movies', 20011027005009);
INSERT INTO thuntnet_reviews VALUES (43, 'Marty', '', 'A guy who can\\\'t seem to get a date, but is such a nice \r\nguy.  He takes care of his family and he always makes \r\nsacrifices.  But in the end, he gets a date, and she \r\nlikes him and all is well.  Uplifting.', 'Ernest Bourgnigine excels in the title role.  The film \r\ncenters around him and with him in the lead it can do \r\nno wrong.', '3', '', 'movies', 20011027005131);
INSERT INTO thuntnet_reviews VALUES (44, 'I know what you did last summer', '', 'Stupid teenagers run over a stranger with their car \r\nand are \\"haunted\\" by him, one year later.', 'Slasher horror pic.  Love-Hewitt is pretty but can\\\'t \r\nact to save her life (which seems to be what most of \r\nthe picture is about).  Some nice gore, a good chase \r\nor two, but not really quality.', '2', '', 'movies', 20011027005405);
INSERT INTO thuntnet_reviews VALUES (45, 'I shot Andy Warhol', '', 'A look inside the life of the woman who wrote the \r\nS.C.U.M. Manifesto and shot Andy Warhol (hence the \r\ncatchy title).', 'Good picture.  Warhol is played well, but not better \r\nthan Cripsin Glover\\\'s performance in The Doors.  The \r\nwoman who plays Valerie does a great job and is truly \r\nterrorifying.', '3', '', 'movies', 20011027005549);
INSERT INTO thuntnet_reviews VALUES (46, 'Requim for a Dream', '', 'Several characters discover drugs, and loose too much \r\nto be described.  Highlight:  The split screen used \r\nperfectly to show the seperation of two characters \r\nwhen they\\\'re incredibly close.', 'Stunning.  Frightning.  Horrifying.  The best anti-\r\ndrug film ever.  I saw this film once and I\\\'m not sure \r\nI ever want to see it again.  A genius at work.', '4', '', 'movies', 20011027005807);
INSERT INTO thuntnet_reviews VALUES (47, 'Little Shop of Horrors', '', 'An evil man eating plant goes wild in this MUSICAL.', 'I hate musicals.  They just keep singing and singing \r\nand singing.  Although the Sadistic Dentist song \r\nstarring Steve Martin makes the film almost worth \r\nwatching.', '2', '', 'movies', 20011027010025);
INSERT INTO thuntnet_reviews VALUES (48, 'Dear God', '', 'Mailmen start answering mail sent to God and doing \r\ngood deeds.', 'Cheesy, boring and unfunny.  Not a bad plot.  Horrible \r\ncourtroom ending though.', '2', '', 'movies', 20011027010107);
INSERT INTO thuntnet_reviews VALUES (49, 'Shadows and Fog', '', 'A man is chased by death througout the city of New \r\nYork. (based on the play: Death)', 'Dark, but beautiful.  Slow moving yet occasionally \r\nfunny.  Dramatic yet mystical.  A good film, but not \r\none of Allen\\\'s better works.', '3', 'Woody Allen', 'movies', 20011027010255);
INSERT INTO thuntnet_reviews VALUES (50, 'Crimes and Misdemenors', '', 'A man (Landau) has his mistress murdered and feels \r\nbad.  Another man (Allen) looses the girl he loves to \r\na pompous ass (Alda).  Highlight:  Allen makes a film \r\nwithin a film where he compairs Alda\\\'s character to \r\nMussolini and Mr. Ed.', 'Funny.  Ups and downs, neurotic.  One of Allen\\\'s \r\nbetter funny ones.  Laundau gives a fantastic \r\nperformance.', '3', 'Woody Allen', 'movies', 20011027010502);
INSERT INTO thuntnet_reviews VALUES (51, 'Truman', '', 'Details the life of President Harry S. Truman', 'Great \\"movie history\\".  Shows Truman as a hard worker, \r\na bad businessman, and a compassionate President.  \r\nSinese does a great job in the title role.  Makes you \r\nfeel kindof bad to think that the Presidental \r\nRetirement program was instituted to keep Truman off \r\nthe dole after his business failed again.  ', '3', '', 'movies', 20011027010630);
INSERT INTO thuntnet_reviews VALUES (52, 'The shop around the corner', '', 'A young man (Stewart) falls in love with his co-\r\nworker.  Ups and downs, he gets fired, he gets re-\r\nhired.  Heartwarming.', 'Good film.  Classic Stewart.  You\\\'ve got Mail was \r\nbased on this picture.  Plot is simplier than Mail, \r\nbut film is much more heartwarming.', '3', '', 'movies', 20011027010753);
INSERT INTO thuntnet_reviews VALUES (53, 'Coyote Ugly', '', 'A hot girl gets a job in a bar.  She records a song \r\nand sings it at the bar to become a major songwriter.  \r\nHoratio Alger exploitive.', 'Lousy.  But marketable.  Tons of hot chicks, random \r\nslow motion shots and lots of music.', '2', '', 'movies', 20011027010918);
INSERT INTO thuntnet_reviews VALUES (54, 'Unbreakable', '', 'Issue #0 for a comic book series.  Genesis.  A man who \r\nis incredibly strong discovers his powers and his \r\nenemy.', 'Slow.  The pacing has one speed, slow as fucking \r\nhell.  The trailer ruined the whole first half for me \r\nand the second half links up to the ending which is \r\nperfect, right up until they bring up this text scroll \r\ndesigned for stupid people.  The text gives a \r\nUNNECCESSARY contuation of the story (like it was \r\nbased on a true story).  The text at the end pretty \r\nmuch destroys any enjoyment I had of the picture. But \r\nI\\\'ll still rate it good, because that\\\'s what it was up \r\ntill that point.', '3', 'M. Night Shamlahan', 'movies', 20011027011149);
INSERT INTO thuntnet_reviews VALUES (56, 'Nashville', '', 'Several characters explore the music scene of \r\nNashville, TN.', 'Muddled.  Too many characters and not enough plot.  \r\nAltman seems a bit out of control and the movie drags \r\nand never seems to go anywhere.', '2', 'Robert Altman', 'movies', 20011027011316);
INSERT INTO thuntnet_reviews VALUES (57, 'Evolution', '', 'A gang of idiots fight aliens.', 'A horrible rip off of Ghostbusters.  Cut to quickly, \r\nfull of stupid fart jokes and other catchlines.  It \r\nmakes me not want to make movies.', '1', '', 'movies', 20011027011404);
INSERT INTO thuntnet_reviews VALUES (58, 'McCabe & Mrs. Miller', '', 'A wild west entrepuner falls in love with a Madam.', 'Slow.  The film is good, the plot is interesting and \r\nthe performances are nice but the film moves \r\nincredibly slowly.  A nice ending though.', '3', '', 'movies', 20011027011505);
INSERT INTO thuntnet_reviews VALUES (59, 'Hurricane, The', '', 'Here is the story of the hurricane.\r\nA man the authorities came to blame.\r\nFor something he never done.\r\nPut in a prison cell, but one time he could have been, \r\nthe champion of the world.', 'Fantastic retelling of a major error of American \r\njustice.  A great performance by Denzel Washington.', '3', '', 'movies', 20011027011628);
INSERT INTO thuntnet_reviews VALUES (60, 'Purple Rose of Cairo, The', '', 'A character from a movie jumps off the screen and \r\nfalls in love with a real woman.', 'Whimsical.  Delightful.  Funny and heartwarming.  ', '3', 'Woody Allen', 'movies', 20011027011813);
INSERT INTO thuntnet_reviews VALUES (61, 'Magnificant Seven, The', '', 'Seven cowboys protect a small village.', 'Bad remake of Kurosawa\\\'s classic The Seven Samurai.  \r\nSteve McQueen rules as always, but the original is far \r\nsuperior.  The film also drags greatly.', '2', '', 'movies', 20011027011906);
INSERT INTO thuntnet_reviews VALUES (62, 'Pretty in Pink', '', 'Cinderella.  Teenage dating.  Redhead wants rich boy, \r\nbut she should date Ducky, the charming nerd character.', 'Ehh.  Not that great, but a typical 80s teen comedy.  \r\nMore romantic than funny, not my favorite John Hughes \r\nfilm.', '3', 'John Hughes', 'movies', 20011027012532);
INSERT INTO thuntnet_reviews VALUES (63, 'Simon Birch', '', 'A freakishly small boy helps foster belief in God for \r\na young boy.  ', 'Sad, heartwarming and well played.  Based on the book \r\nA prayer for Owen Meany by John Irving.  The movie has \r\nsome good twists and turns, some bad acting by Ashley \r\nJudd and some great acting from the little actor \r\nplaying the title role.', '3', '', 'movies', 20011027012656);
INSERT INTO thuntnet_reviews VALUES (64, 'The Odd Couple', '', 'Two people who shouldn\\\'t live together do.  They \r\nfight, they fight and it\\\'s hilarious.', 'Great performances coupled with great writing.  \r\nPerformances by Lennon and Mathau.  Writing by Neil \r\nSimon.  Funny, but doesn\\\'t loose that \\"play\\" feeling.', '3', '', 'movies', 20011027163050);
INSERT INTO thuntnet_reviews VALUES (65, 'Muriel\\\'s Wedding', '', 'Wierd british woman wants to get married.', 'Wierd british comedy.  Lots and lots of Abba Music.  \r\nFunny in parts, british in other parts.  Quirky.', '3', '', 'movies', 20011027013012);
INSERT INTO thuntnet_reviews VALUES (66, 'Hope and Glory', '', 'A look at the homelife during the Blitz of WWII.  \r\nHighlight: The gang of little boys bribes a girl to \r\nshow them her privates, hilarious.', 'Interesting look at the children of WWII.  Nice to see \r\nthe war from a different angle.  Also nice to see an \r\nacurate portryal of what children would do in the \r\nmiddle of a bombed out city.', '3', '', 'movies', 20011027013151);
INSERT INTO thuntnet_reviews VALUES (67, 'Paths of Glory', '', 'A general is blamed for not forcing his men to \r\ncommitte suicide on the battlefield.  Courtroom drama, \r\nthree men are held accountable and tried of \r\ncowardess.  They die.', 'Well directed.  Plot is a little less than desirable.  \r\nGood ending.  Great performance by Kurt Douglass.  A \r\nKubrick film before he gained total control, but still \r\na Kubrick film.', '3', 'Stanley Kubrick', 'movies', 20011027013501);
INSERT INTO thuntnet_reviews VALUES (68, 'Finding Forester', '', 'Good Will Hunting on racial lines.  Sean Connery \r\npretends to be J.D. Saldinger and teaches a young \r\nblack man to write.  Uplifting.', 'I love J.D. Saldinger who this film was nominally \r\nbased on.  I liked it for that reason.  Otherwise it\\\'s \r\npretty much like Good Will Hunting, even had the same \r\ndirector.', '3', 'Gus Van Sant', 'movies', 20011027013622);
INSERT INTO thuntnet_reviews VALUES (69, 'Spike, Mike, Slackers and Dikes', '1995', 'Non-Fiction.  An overview of American Independant film \r\nfrom the 80s to the mid ninties.', 'Good book.  Historical, informatative and funny. Good \r\ninfo about Spike Lee, Michael Moore, Kevin Smith and \r\nmore.  Insight into how an independant film goes from \r\na film to show your family into a film that the world \r\ngoes ape shit over.', '3', 'John Pierson', 'books', 20011110143826);
INSERT INTO thuntnet_reviews VALUES (70, 'Music for Chameleons', '1975', 'Multiple plots.  Collection of short stories, self \r\ninterviews and jouranlistic fiction.', 'A good book.  Highlights: Mr. Jones, a story about a \r\nmysterious man, never quite explained.  Other \r\nhighlighs include a self interview with Capote in the \r\nend of the book and a description of a day spent with \r\nMarylin Monroe.', '3', 'Truman Capote', 'books', 20011110144017);
INSERT INTO thuntnet_reviews VALUES (71, 'Regulators, The', '1996', 'An evil spirit enchants a kid, then uses the child\\\'s \r\nheroes (cartoon characters and cowboys) to wreck havoc \r\nin a suburban setting.', 'Not that great.  Filled with cop outs, points where \r\nKing describes something as like a pop culture object \r\ninstead of actually describing it.  The snow was \r\nfalling like the snow in the movie It\\\'s a wonderful \r\nlife.  Pretty lame.  Story is interesting from a \r\nsurbanan invasion point of view but poor from another \r\nchild enchanted with demon point of view.', '2', 'Richard Bachman', 'books', 20011110144258);
INSERT INTO thuntnet_reviews VALUES (72, 'Lord of the Rings, The', '1954', 'Mystical.  A hobbit must travel far to destroy an evil \r\nring.  Many twists and turns.', 'Slow but good.  Fellowship drags due to too much \r\ntravel, approx 300 pages of wandering.  Second half \r\npicks up well by adding more characters and telling \r\ntheir stories in alternatating chapters, a tool \r\nTolkien uses well to make the other books more \r\ninteresting.  <BR><BR>\r\n\r\nThe wonder and the beauty of the book is the world \r\ncreated by Tolkien.  He mentions minor things like \r\nlegends (which you know are not even written down) but \r\nyou buy that they exist in the world he\'s created.  \r\nIt\'s size is incredible and the travel in the story \r\nhelps to highlight and give the reader a good tour of \r\nthat world.', '3', 'J.R.R. Tolkien', 'books', 20011110144712);
INSERT INTO thuntnet_reviews VALUES (73, 'Microserfs', '1995', 'Nerds at microsoft join a startup and regain their \r\nlives.  Sad ending, unexpected and unneccessary.', 'Stunning.  Like my life.  Similarities abound, from \r\nworship of simpsons, to Costco addiction (where one \r\nbuys 10,000 straws, planning never to need to buy \r\nstraws ever again).  A laugh on every page, characters \r\nthat leap out at you because you know people just like \r\nthem in real life.', '4', 'Douglas Coupland', 'books', 20011110144951);
INSERT INTO thuntnet_reviews VALUES (74, 'Harry Potter and the Sorcerer\'s Stone', '1998', 'A young boy discovers that he is the son of a great \r\nwizard (and witch) and joins a wizard school. Similar \r\nto Star Wars, Hitchhiker\'s Guide, and of course The \r\nLord of the Rings.', 'Decent.  I read it in a day, so it was interesting and \r\ncute.  Predictable, like a bond film, when they \r\ndescribe something in the begining it shows up a few \r\npages later.  Basic writing, but fun to read.', '3', 'J.K. Rowling', 'books', 20011111102049);
INSERT INTO thuntnet_reviews VALUES (75, 'Generation X', '1991', 'Three disafected youths escape their lives to the \r\ndesert to tell stories and try to figure life out.', 'Good.  Good stories, good definations in the margins, \r\nsemi-disposable sweedish furnature, mid-twenties \r\nbreakdown, jampenes minimalism.  A fun read, though \r\nprovoking, well written.', '3', 'Douglas Coupland', 'books', 20011111102224);
INSERT INTO thuntnet_reviews VALUES (76, 'Downsize This!', '1996', 'Non-fiction/humor.  Collection of chapters ("essays") \r\non various political issues.', 'Good.  Moore is funny and intelligent, although having \r\nwatched all of his movies and most of his TV shows, \r\nthe book does seem a bit repetative, but this is \r\nsimply because I\'ve already seen him talk about most \r\nof the issues he raises in this book.', '3', 'Michael Moore', 'books', 20011112222552);
INSERT INTO thuntnet_reviews VALUES (77, 'Adventures in a TV Nation', '1998', 'Non fiction.  The behind the scenes story of Michael \r\nMoore\'s television show TV Nation.  Details several of \r\ntheir shows.', 'Funny, but sad because the show was not renewed.  \r\nTypical Moore humor, going places and getting kicked \r\nout.  Highlights include "sending a KGB spy to spy on \r\nUnsolved Mysteries", "mike trying to find the missile \r\nthat pointed at Flint, MN", "Haulin\' communism" \r\nand "Junk Mail", where they sent letters requesting \r\nmoney for Serial Killer Jeffery Dahmer, and recieved \r\nmoney.', '3', 'Michael Moore', 'books', 20011114103614);
INSERT INTO thuntnet_reviews VALUES (78, 'Glengarry Glen Ross', '1982', 'The troubles of salesmen are explored in this awesome \r\nplay.', '(not a book, a play)  Great play.  Well written, very \r\nfast, very mamet.  Shorter and simplier than the movie \r\nversion.  Four acts, no "coffee is for closers" scene \r\nand simpler in structure.', '3', 'David Mamet', 'books', 20011114131655);
INSERT INTO thuntnet_reviews VALUES (79, 'Smith of Wooton Major & Farmer Giles of Ham', '1969', 'Two novella length stories.  Wooton Major is about \r\nfairies and cooking.  While Farmer Giles is about \r\ndragons and giants.', 'Interesting fantasies.  Legendary.  Similar to \r\nBeowulf, Sir Gwain, classic english literature style.  \r\nLight, joyful, shiney.', '3', 'J.R.R. Tolkien', 'books', 20011114132201);
INSERT INTO thuntnet_reviews VALUES (80, 'Zen and the art of screenwriting', '1996', 'Non fiction.  Interviews with screen writers and \r\nadvice from former UCLA proffessor William Froug.', 'Interesting.  Some famous screenwriters, some not so \r\nfamous, facinating stories and insights none the \r\nless.  Suffers slightly from it\'s horrible title.', '3', 'William Froug', 'books', 20011115194941);
INSERT INTO thuntnet_reviews VALUES (81, 'Dave Berry\'s Complete Guide to Guys', '1995', 'Non fiction (Humor).  Berry writes about guys through \r\nthe ages, from medievil times until modern times (ex: \r\nusing a trebuchet to launch a dead horse, or using a \r\ntrebuchet to launch a buick).', 'Funny and brief.  Two good qualities.  I read it in a \r\nday thinking that I had read it before.  I probably \r\nhad, but it was still damn funny.  Hilights: Launching \r\nTrebuchets, Corvair enthusiasts blowing up vacume \r\ncleaners, and much much more.  PS: Don\'t forget to \r\nfart.', '3', 'Dave berry', 'books', 20011118220158);
INSERT INTO thuntnet_reviews VALUES (82, 'Bridget Jones: the edge of reason', '1999', 'Sequal to Bridget Jones\' Diary.  Jones, now with a \r\nboyfriend, manages to screw that up, get locked up in \r\nThailand, but gets free and gets back together with \r\nboyfriend.', 'Light. Fun like original.  Wild story twists with \r\nThailand, naked mexican houseboy, etc.  Character \r\nstill likable though.  Decent for a sequal.', '3', 'Helen Fielding', 'books', 20011127154412);
INSERT INTO thuntnet_reviews VALUES (83, 'Cape Fear', '1962', 'A man released from jail seeks revenge.  Gregory Peck \r\ntries to protect his family from this madman (Mitchum).', 'Cool.  Been paradied too much so it\'s tough to judge \r\nit, but it is still really cool.  Nice lighting, great \r\nmusic by Bernard Herman (psycho, taxi driver).  ', '3', '', 'movies', 20011128165531);
INSERT INTO thuntnet_reviews VALUES (84, 'Henry Fool', '1998', 'A garbage man writes an epic poem or is it \r\npornography.  He is inspired to write by a wandering \r\nex-child molester.  ', 'Fantastic.  Nice pacing, good lighting, fantastic \r\nacting.  The character of fool is very interesting.  \r\nSimilar to Polonious.  Is he a fool or is he a \r\ngenius.  ', '4', 'Hal Hartly', 'movies', 20011128165801);
INSERT INTO thuntnet_reviews VALUES (85, 'Luzhen Defence, The', '', 'A brilliant withdrawn chess player falls in love and \r\nhas to choose between chess and life.  Sad ending:  he \r\ncommitts suicide.', 'Excellent.  Gorris (Question of Silence, Antionia\'s \r\nLine) does a great job by bringing the game of chess \r\ninto the direction of the film by shooting from above, \r\nnice reveals, etc.  John Turtoro is excellent in the \r\nreclusive lead.', '3', 'Marleen Gorris', 'movies', 20011128170149);
INSERT INTO thuntnet_reviews VALUES (86, 'Urban Legends 2: Final Cut', '', 'Film students making a film about urban legends get \r\nkilled by their film proffessor who uses urban legends \r\nto kill them.  ', 'Inferior to the original.  Too many long girl getting \r\nchased by a monster scenes.  Also had the stupid kid \r\ndies then we introduce his twin, who is played by the \r\nsame actor, like a soap opera.  Also has a stupid film \r\nwithin a film, ending within an ending thing.  ', '2', '', 'movies', 20011128170553);
INSERT INTO thuntnet_reviews VALUES (87, 'Spy Game', '2001', 'Old CIA agent trained young CIA agent.  Young CIA \r\nagent ignores his teaching and falls for a girl and \r\nthen puts his life on the line for her but he and she \r\nare saved by old CIA agent.', 'Marred by a terrible flashback structure.  Plot \r\nin "present time" moving forward is interesting, but \r\nthey keep flashing back to pointless and stupid \r\nflashbacks.  Also unbelievable because characters do \r\nnot age.  In the age of super makeup and digital \r\neffects we should be able to do better.', '2', 'Tony Scott', 'movies', 20011128170858);
INSERT INTO thuntnet_reviews VALUES (88, 'Generation of Swine', '', 'Collection of articles from the 80s.  Mainly focusing \r\non the 1988 presidential election, and the Iran Contra \r\naffair.', 'Typical Hunter.  Gambling on candidates.  Madness, \r\nsatelite tv, the end of Gary Heart, Ted Kenedy.  The \r\nattempted end of Reagan/Bush, but they were saved by \r\nan excellent performance by Oliver North.', '3', 'Hunter S. Thompson', 'books', 20011128171057);
INSERT INTO thuntnet_reviews VALUES (89, 'Dead Man', '', 'William Blake (Johnny Depp) travels to the wild west \r\nand looses his job.  He meets a girl and then gets in \r\na gun fight with her boyfriend, kills him, the girl \r\nkilled and he\'s on the run.  Travels with wierd indian \r\nand becomes killer.  Eventually dies.', 'Slow.  Jarmush is too slow.  Too many fades to black.  \r\nactors are good but movie drags like you won\'t believe.', '2', 'Jim Jarmush', 'movies', 20011128172439);
INSERT INTO thuntnet_reviews VALUES (90, 'Spanish Prisoner, The', '', 'A man developing a process is caught in a complicated \r\nconfidence scam.  People try to steal the process.  \r\nLots of twists and turns.', 'Mamet-tastic.  Well written, well acted.  Major kudos \r\ngo to Rebecca Pidgen (mrs. mamet), and Steven Martin \r\n(who is actually serious in this film).  Dialouge is \r\nfantastic.', '3', 'David Mamet', 'movies', 20011128172720);
INSERT INTO thuntnet_reviews VALUES (91, 'Thin Blue Line, The', '', 'Documentary.  A man is falsely accused of murdering a \r\npolice officer.', 'Good, powerful, but too many re-enactments of the \r\ncrime.  Seems too much like a drama than a documentary \r\nas well, but still worthwile because of its incredible \r\npower.', '3', 'Errol Morris', 'movies', 20011128172935);
INSERT INTO thuntnet_reviews VALUES (92, 'Winslow Boy, The', '', 'English.  A young boy is kicked out of school for a \r\ncrime he didn\'t commit.  His family comes together and \r\nfights for his honor.', 'Excellent.  Rebecca Pigeon is fantastic.  The movie is \r\na little slow and the plot drags a bit but it is still \r\npacked with fantastic Mamet dialouge.', '3', 'David Mamet', 'movies', 20011128173144);
INSERT INTO thuntnet_reviews VALUES (93, 'Cape Fear', '1991', 'Same plot as Cape Fear (1962).  But slightly \r\ndifferent.  Man who is chased by evil convict is \r\nguilty.  He fixed the convict\'s case so he would \r\nloose, and was cheating on his wife on multiple \r\noccasions.  The small twists made to the story make it \r\nall the much better.', 'Thrilling.  Scorssese takes on Hitchock, and makes a \r\nfilm worth of his name.  Hermman\'s score is back, \r\nbeautifully enhanced by a DTS track (on the DVD \r\nversion I watched).  DeNiro is stunning and creates a \r\nfar more frightning Max Cady than the original.  Also \r\nthere is some amazing excitement building camera work \r\nin the Raquetball scene, the scene where he beats up \r\nthe girl and the closing the shades scene.  The wires \r\ntied to the bear is also incredibly suspenceful.  A \r\nremake that is superior to the original.', '4', 'Martin Scorssese', 'movies', 20011129123142);
INSERT INTO thuntnet_reviews VALUES (94, 'Harry Potter and the Chamber of Secrets', '', 'Harry is back at Hogwarts for Year 2.  He and his \r\nfriends fight another monster.  They win.', 'Light.  Good story, good characters.  Not the greatest \r\nwork of literature, but entertaining.', '3', 'J.K. Rowling', 'books', 20011130155125);
INSERT INTO thuntnet_reviews VALUES (95, 'Boxing Helena', '', 'A crazed surgen dreams about "boxing helena", ie: \r\nCutting off her arms and legs and keeping her locked \r\nup in his house.  Pretty sick.', 'Creepy, but what else would you expect from David \r\nLynch\'s daughter.  A fucked up story indeed, but I \r\nfeel it would have played better as a comedy.  The \r\nfirst half seems like a porno while you keep waiting \r\nfor the second half to turn into slapstick comedy.\r\n', '2', 'Jennifer Lynch', 'movies', 20011130155309);
